def _short_stage_date(v):
    s = str(v or '').strip()
    if not s or s in ('?', 'nan', 'None'):
        return ''
    if len(s) >= 10 and s[4] == '-' and s[7] == '-':
        return s[5:10]
    return s[:5]


def _row_num(row, *keys, default=0.0):
    for k in keys:
        try:
            v = row.get(k, default)
            if pd.isna(v):
                continue
            return float(v)
        except Exception:
            continue
    return float(default)


def _row_text(row, *keys, default=''):
    for k in keys:
        try:
            v = row.get(k, default)
            if pd.isna(v):
                continue
            s = str(v).strip()
            if s:
                return s
        except Exception:
            continue
    return default


def build_kki_profile(row) -> dict:
    vol = _row_num(row, 'Volume', '거래량', default=0.0)
    vma20 = max(_row_num(row, 'VMA20', default=0.0), 1.0)
    attack = _row_num(row, '수박공격점수', 'wm_attack_score', default=0.0)
    blue = _row_num(row, '수박파란점선점수', 'wm_blue_score', default=0.0)
    preempt = _row_num(row, '선취점수', '단테점수', default=0.0)
    breakout = _row_num(row, '돌파점수', default=0.0)
    n_score = _row_num(row, 'N점수', default=0.0)
    safe_score = _row_num(row, '안전점수', default=0.0)
    obv = _row_num(row, 'OBV_Slope', 'OBV', default=0.0)
    vol_ratio20 = vol / vma20 if vma20 > 0 else 0.0
    reanchor = bool(row.get('5일재안착', False) or _row_text(row, '5일재안착태그', default=''))
    wick_ok = bool(row.get('수박정제_wick_ok', True))
    candle_ok = bool(row.get('수박정제_candle_ok', True))
    cloud_ok = bool(row.get('수박정제_cloud_ok', True))

    burst = min(35, int(vol_ratio20 * 8) + int(max(attack, blue) * 2) + (8 if breakout >= 80 else 0))
    recovery = min(25, (10 if reanchor else 0) + (8 if candle_ok else 0) + (7 if cloud_ok else 0))
    spotlight = min(20, int(max(n_score, safe_score) / 120) + (5 if preempt >= 50 else 0) + (4 if obv > 0 else 0))
    trap = 0
    reasons_bad = []
    if not wick_ok:
        trap += 8; reasons_bad.append('윗꼬리')
    if not candle_ok:
        trap += 6; reasons_bad.append('캔들약함')
    if not cloud_ok:
        trap += 6; reasons_bad.append('구름/저항')
    if vol_ratio20 < 0.9:
        trap += 5; reasons_bad.append('거래량약함')

    kki_score = max(0, min(100, burst + recovery + spotlight - trap))
    if kki_score >= 75:
        kki_tag = '🔥끼강'
    elif kki_score >= 58:
        kki_tag = '⚡끼있음'
    elif kki_score >= 40:
        kki_tag = '🟡끼보통'
    else:
        kki_tag = '😴끼약'

    change = _row_num(row, '등락률', 'Change%', 'Change', default=0.0)
    today_p = _row_num(row, 'today_p', default=0.0)
    today_f = _row_num(row, 'today_f', default=0.0)
    today_i = _row_num(row, 'today_i', default=0.0)
    cum5_f = _row_num(row, 'cum5_f', default=0.0)
    cum5_i = _row_num(row, 'cum5_i', default=0.0)
    close = _row_num(row, '종가', 'Close', '현재가', default=0.0)
    low = _row_num(row, '저가', 'Low', default=0.0)
    high = _row_num(row, '고가', 'High', default=0.0)
    recov = (close - low) / max(high - low, 1e-6) if high > low else 0.0

    absorb_score = 0
    absorb_reasons = []
    if today_p < 0 and (today_f > 0 or today_i > 0):
        absorb_score += 35; absorb_reasons.append('개인매도흡수')
    if change <= -1.0 and (today_f + today_i) > 0:
        absorb_score += 20; absorb_reasons.append('하락중받아먹기')
    if vol_ratio20 >= 1.3:
        absorb_score += 15; absorb_reasons.append('거래량동반')
    if recov >= 0.55:
        absorb_score += 15; absorb_reasons.append('종가회복')
    if (cum5_f + cum5_i) > 0:
        absorb_score += 10; absorb_reasons.append('5일누적유입')
    absorb_score = max(0, min(100, absorb_score))
    if absorb_score >= 70:
        absorb_tag = '🧲투매흡수강'
    elif absorb_score >= 45:
        absorb_tag = '🧲받아먹기'
    elif absorb_score >= 25:
        absorb_tag = '🪙약흡수'
    else:
        absorb_tag = ''

    reasons_good = []
    if vol_ratio20 >= 1.5: reasons_good.append('거래량확산')
    if reanchor: reasons_good.append('재안착')
    if cloud_ok: reasons_good.append('저항위치양호')
    if obv > 0: reasons_good.append('OBV우상향')
    if breakout >= 80: reasons_good.append('돌파에너지')
    if blue >= 5: reasons_good.append('재점화')

    reason_parts = []
    if reasons_good:
        reason_parts.append('장점:' + ' / '.join(reasons_good[:4]))
    if reasons_bad:
        reason_parts.append('주의:' + ' / '.join(reasons_bad[:4]))
    if absorb_reasons:
        reason_parts.append('흡수:' + ' / '.join(absorb_reasons[:4]))

    return {
        'kki_score': int(kki_score),
        'kki_tag': kki_tag,
        'absorb_score': int(absorb_score),
        'absorb_tag': absorb_tag,
        'kki_reason': ' | '.join(reason_parts),
    }


def enrich_row_with_human_commentary(row):
    base = dict(row) if isinstance(row, dict) else row.to_dict()
    pass_bundle = get_pass_stage_bundle(base)
    easy = build_easy_interpretation(base)
    score_summary = build_score_summary(base)
    kki = build_kki_profile(base)

    base['pass_stage'] = pass_bundle['pass_stage']
    base['pass_title'] = pass_bundle['pass_title']
    base['pass_desc'] = pass_bundle['pass_desc']
    base['easy_interpretation'] = easy['easy_interpretation']
    base['action_summary'] = easy['action_summary']
    base['caution'] = easy['caution']
    base['final_label'] = easy['final_label']
    base['need_check'] = easy.get('need_check', '')
    base['score_summary'] = score_summary
    base['kki_score'] = kki['kki_score']
    base['kki_tag'] = kki['kki_tag']
    base['absorb_score'] = kki['absorb_score']
    base['absorb_tag'] = kki['absorb_tag']
    base['kki_reason'] = kki['kki_reason']

    block_lines = []
    if base['pass_title']:
        block_lines.append(f"🧩 PASS 해석: {base['pass_title']}")
    if base['pass_desc']:
        block_lines.append(f"→ {base['pass_desc']}")
    if base.get('kki_tag'):
        kline = f"🎭 끼점수: {base['kki_tag']} {base['kki_score']}"
        if base.get('absorb_tag'):
            kline += f" | {base['absorb_tag']} {base['absorb_score']}"
        block_lines.append(kline)
    if base.get('kki_reason'):
        block_lines.append(f"🧲 끼/흡수 해설: {base['kki_reason']}")
    if base['easy_interpretation']:
        block_lines.append(f"🧠 쉬운 해석: {base['easy_interpretation']}")
    if base.get('need_check'):
        block_lines.append(f"🔍 확인 기준: {base['need_check']}")
    if base['action_summary']:
        block_lines.append(f"🎯 대응 요약: {base['action_summary']}")
    if base['caution']:
        block_lines.append(f"⚠️ 주의 포인트: {base['caution']}")
    if base['final_label']:
        block_lines.append(f"✅ 최종 판정: {base['final_label']}")
    if base['score_summary']:
        block_lines.append(f"🧮 점수 해석: {base['score_summary']}")
    base['interpretation_block'] = "\n".join(block_lines)
    return base

def append_interpretation_to_block(block: str, row) -> str:
    if not isinstance(block, str):
        block = str(block or '')
    if '🧠 쉬운 해석:' in block:
        return block
    enriched = enrich_row_with_human_commentary(row)
    extra = enriched.get('interpretation_block', '') or ''
    if not extra:
        return block.rstrip()
    return block.rstrip() + '\n\n' + extra.strip() + '\n'


def build_integrated_stock_block(block: str, row) -> str:
    return append_interpretation_to_block(block, row)

