        is_2nd_buy = False
        is_rn_signal = False
        
        if lower_rn and upper_rn:
            lookback_df = df.iloc[max(0, raw_idx-20) : raw_idx]
            hit_upper = any(lookback_df['High'] >= upper_rn * 1.04)
