def classify_style(row):
    vol_ratio = row['ATR'] / row['Close'] if row['Close'] > 0 else 0
    if (row['BB40_Width'] < 12 and row['MA_Convergence'] < 3 and row['ADX'] < 25):
        return "SWING"
    elif (0.02 <= vol_ratio <= 0.05 and row['ADX'] >= 25):
        return "SCALP"
    return "NONE"
  

# =============================================================
# 📐 피봇 포인트 + 피보나치 + ATR 목표가 계산 (Ver 27.18)
# =============================================================

def calc_pivot_levels(df: pd.DataFrame) -> dict:
    """
    전일 고/저/종가 기반 피봇 포인트 계산.
    PP  = (H + L + C) / 3
    R1  = 2*PP - L
    R2  = PP + (H - L)
    R3  = H + 2*(PP - L)
    S1  = 2*PP - H
    S2  = PP - (H - L)
    S3  = L - 2*(H - PP)
    """
    if df is None or len(df) < 2:
        return {}

    prev = df.iloc[-2]
    H = float(prev['High'])
    L = float(prev['Low'])
    C = float(prev['Close'])

    PP = (H + L + C) / 3
    R1 = round(2 * PP - L)
    R2 = round(PP + (H - L))
    R3 = round(H + 2 * (PP - L))
    S1 = round(2 * PP - H)
    S2 = round(PP - (H - L))
    S3 = round(L - 2 * (H - PP))

    return {
        'PP': round(PP), 'R1': R1, 'R2': R2, 'R3': R3,
        'S1': S1, 'S2': S2, 'S3': S3,
    }


def calc_fibonacci_levels(df: pd.DataFrame, lookback: int = 20) -> dict:
    """
    최근 N봉 고점~저점 기준 피보나치 되돌림 레벨.
    상승 추세: 저점에서 고점으로의 되돌림
    0%, 23.6%, 38.2%, 50%, 61.8%, 78.6%, 100%
    """
    if df is None or len(df) < lookback:
        return {}

    recent = df.tail(lookback)
    swing_high = float(recent['High'].max())
    swing_low  = float(recent['Low'].min())
    diff       = swing_high - swing_low

    if diff <= 0:
        return {}

    return {
        'fib_0':    round(swing_high),
        'fib_236':  round(swing_high - diff * 0.236),
        'fib_382':  round(swing_high - diff * 0.382),
        'fib_500':  round(swing_high - diff * 0.500),
        'fib_618':  round(swing_high - diff * 0.618),
        'fib_786':  round(swing_high - diff * 0.786),
        'fib_100':  round(swing_low),
        'swing_high': round(swing_high),
        'swing_low':  round(swing_low),
    }


def calc_atr_targets(row: pd.Series, close: float) -> dict:
    """
    ATR 기반 동적 목표가/손절가 계산.
    1차 목표: 현재가 + ATR × 2
    2차 목표: 현재가 + ATR × 3.5
    손절:     현재가 - ATR × 1.5  (역매공파 -5% 기준과 취사선택)
    """
    atr = float(row.get('ATR', 0) or 0)
    if atr <= 0:
        return {}

    return {
        'atr_val':    round(atr),
        'target_1':   round(close + atr * 2),     # 1차 목표
        'target_2':   round(close + atr * 3.5),   # 2차 목표
        'stop_atr':   round(close - atr * 1.5),   # ATR 손절
        'risk_reward': round((atr * 2) / (atr * 1.5), 1),  # 기본 RR비율
    }


def calc_support_resistance(df: pd.DataFrame, row: pd.Series, close: float) -> dict:
    """
    현재가 기준 가장 가까운 지지/저항 레벨 찾기.
    피봇 + 피보나치 + BB밴드 + MA를 통합해서 가장 근접한 레벨 반환.
    """
    pivot  = calc_pivot_levels(df)
    fib    = calc_fibonacci_levels(df)
    atr_t  = calc_atr_targets(row, close)

    # 모든 레벨 수집
    all_levels = []

    # 피봇 레벨
    for k, v in pivot.items():
        if v > 0:
            all_levels.append(('pivot_' + k, v))

    # 피보나치 레벨
    for k, v in fib.items():
        if v > 0 and k.startswith('fib'):
            all_levels.append((k, v))

    # MA 레벨
    for ma in ['MA20', 'MA40', 'MA60', 'MA112', 'MA224']:
        val = float(row.get(ma, 0) or 0)
        if val > 0:
            all_levels.append((ma, round(val)))

    # BB 레벨
    for bb in ['BB_Upper', 'BB_Lower', 'BB40_Upper', 'BB40_Lower']:
        val = float(row.get(bb, 0) or 0)
        if val > 0:
            all_levels.append((bb, round(val)))

    # 현재가 위: 저항, 아래: 지지
    resistances = sorted([(n, v) for n, v in all_levels if v > close], key=lambda x: x[1])
    supports    = sorted([(n, v) for n, v in all_levels if v < close], key=lambda x: x[1], reverse=True)

    nearest_res = resistances[0] if resistances else ('없음', 0)
    nearest_sup = supports[0]    if supports    else ('없음', 0)

    return {
        'pivot':        pivot,
        'fib':          fib,
        'atr_targets':  atr_t,
        'nearest_res':  nearest_res,
        'nearest_sup':  nearest_sup,
        'resistances':  resistances[:3],   # 상위 3개 저항
        'supports':     supports[:3],      # 상위 3개 지지
    }

def get_target_levels(current_price):
    upper_rns = [rn for rn in RN_LIST if rn > current_price]
    lower_rns = [rn for rn in RN_LIST if rn <= current_price]
    upper = upper_rns[0] if upper_rns else None
    lower = lower_rns[-1] if lower_rns else None
    return lower, upper

def analyze_weekly_trend(ticker, name):
    try:
        df_daily = fdr.DataReader(ticker, start=(datetime.now()-timedelta(days=730)))
        if len(df_daily) < 200: return []

        df = df_daily.resample('W-MON').agg({
            'Open': 'first', 'High': 'max',
            'Low': 'min', 'Close': 'last', 'Volume': 'sum'
        })

        df['MA20_W'] = df['Close'].rolling(window=20).mean()
        df['BB20_Upper_W'] = df['MA20_W'] + (df['Close'].rolling(window=20).std() * 2)
        df['OBV_W'] = (np.sign(df['Close'].diff()) * df['Volume']).fillna(0).cumsum()
        df['OBV_MA10_W'] = df['OBV_W'].rolling(window=10).mean()

        row = df.iloc[-1]
        prev = df.iloc[-2]

        is_weekly_break = prev['Close'] <= prev['BB20_Upper_W'] and row['Close'] > row['BB20_Upper_W']
        is_weekly_acc = row['OBV_W'] > row['OBV_MA10_W']
        
        df['MA5_W'] = df['Close'].rolling(window=5).mean()
        is_weekly_gc = prev['MA5_W'] <= prev['MA20_W'] and row['MA5_W'] > row['MA20_W']

        tags = []
        w_score = 100
        
        if is_weekly_break: tags.append("🚨주봉돌파"); w_score += 30
        if is_weekly_acc: tags.append("🌊주간매집"); w_score += 15
        if is_weekly_gc: tags.append("✨주간GC"); w_score += 15

        if not tags: return []

        return [{
            '날짜': df.index[-1].strftime('%Y-%m-%d'),
            '종목명': f"[주간] {name}",
            '주간화력': w_score,
            '이격도_W': int((row['Close']/row['MA20_W'])*100),
            '구분': " ".join(tags),
            '진단': "주봉 단위 강력 추세 전환 포착"
        }]
    except Exception as e:
        return []

def generate_stage_ai_tip(row):
    try:
        stage = str(row.get('단계상태', '') or '')
        safe_score = safe_int(row.get('안전점수', 0))
        nscore = safe_int(row.get('N점수', 0))
        obv = safe_float(row.get('OBV기울기', 0))
        rsi = safe_float(row.get('RSI', 50))
        pre = bool(row.get('예비돌반지', False))
        pre_exact = bool(row.get('예비돌반지HTS정확복제', False))
        pre_lite = bool(row.get('신규예비돌반지Lite', False))

        reasons = []
        cautions = []

        if pre_exact:
            reasons.append("장기 구조 조건까지 맞물린 HTS 정확복제형 예비돌반지 후보라 자리 해석의 질이 높은 편입니다")
        elif pre:
            reasons.append("예비돌반지 계열로 잡혀 재돌파 감시 가치가 있습니다")
        elif pre_lite:
            reasons.append("신규상장/짧은 이력 구간에서 대체 패턴인 신규예비돌반지 Lite가 감지되었습니다")

        if stage == "PASS_A":
            reasons.append("초동 파동 시작 구간이라 첫 돌파 흐름을 확인하는 자리입니다")
        elif stage == "PASS_B":
            reasons.append("재파동 초입으로 수급만 유지되면 한 번 더 뻗을 여지가 있습니다")
        elif stage:
            reasons.append(f"{stage} 단계로 분류되어 현재 구조의 위치 해석이 가능합니다")

        if obv > 0:
            reasons.append("OBV 기울기가 살아 있어 수급의 방향성은 나쁘지 않습니다")
        if safe_score >= 70:
            reasons.append("안전점수가 높은 편이라 무너지기 전까지는 관찰 우선순위를 둘 수 있습니다")
        if nscore >= 80:
            reasons.append("종합 점수가 높아 다른 후보와 비교해도 우선 검토할 만합니다")

        if rsi >= 72:
            cautions.append("다만 RSI가 과열권이면 바로 추격보다 눌림 확인이 더 중요합니다")
        elif rsi <= 35:
            cautions.append("RSI가 낮으면 아직 반등 확인이 덜 된 약세 구간일 수 있습니다")

        if safe_score < 50:
            cautions.append("안전점수가 낮아 구조가 예뻐 보여도 실패 시 흔들림이 커질 수 있습니다")

        if not reasons:
            reasons.append("아직 강한 확신 구간이라기보다 추가 확인이 필요한 중립 위치입니다")
        if not cautions:
            cautions.append("다만 무효화 기준 없이 보는 자리로는 애매하니 전일 저점이나 핵심 이평 이탈은 반드시 체크해야 합니다")

        body = f"{reasons[0]}. "
        if len(reasons) > 1:
            body += " ".join(reasons[1:]) + " "
        body += " ".join(cautions)
        return body.strip()
    except Exception:
        return "타이밍 애매, 추가 확인 필요"



