# =================================================
# ✅ 전역 공용 숫자 변환 헬퍼
# =================================================
def safe_float(x, default=0.0):
    try:
        if x is None:
            return default
        if isinstance(x, str):
            x = x.replace(',', '').strip()
            if x == '':
                return default
        return float(x)
    except Exception:
        return default


def safe_int(x, default=0):
    try:
        return int(round(safe_float(x, default)))
    except Exception:
        return default

def coerce_numeric_columns(df: pd.DataFrame, columns):
    """문자열/콤마 섞인 숫자 컬럼을 안전하게 숫자로 변환"""
    if df is None or len(df) == 0:
        return df
    out = df.copy()
    for col in columns:
        if col in out.columns:
            out[col] = pd.to_numeric(
                out[col].astype(str).str.replace(',', '', regex=False).str.strip(),
                errors='coerce'
            )
    return out

def normalize_leader_scanner_columns(df: pd.DataFrame) -> pd.DataFrame:
    """대장주 스캐너/내부 로직이 한글·영문 컬럼을 모두 쓰도록 별칭을 같이 만든다."""
    if df is None or len(df) == 0:
        return df
    out = df.copy()

    alias_groups = {
        '종가': ['종가', 'Close', 'close', 'Price', 'price'],
        '시가총액': ['시가총액', 'Marcap', 'MarCap', 'marcap', 'market_cap'],
        '거래량': ['거래량', 'Volume', 'volume'],
        '거래대금': ['거래대금', 'Amount', 'Value', 'Turnover', 'amount', 'value'],
        '종목명': ['종목명', 'Name', 'name'],
        '종목코드': ['종목코드', 'Code', 'code'],
    }

    for target, candidates in alias_groups.items():
        if target not in out.columns:
            for cand in candidates:
                if cand in out.columns:
                    out[target] = out[cand]
                    break

    # 내부 기존 영문 로직도 유지되게 역방향 별칭도 보장
    reverse_alias = {
        'Close': '종가',
        'Marcap': '시가총액',
        'Volume': '거래량',
        'Amount': '거래대금',
        'Name': '종목명',
        'Code': '종목코드',
    }
    for eng, kor in reverse_alias.items():
        if eng not in out.columns and kor in out.columns:
            out[eng] = out[kor]

    return out



# ─────────────────────────────────────────────────────────────
# 수박상태 파이썬 검색 엔진 (HTS 실험판을 Python 스캔용으로 이식)
# 주의: 원본 수박지표 1:1 복제가 아니라 "하락정지/재정비/재점화" 상태 검색용
# ─────────────────────────────────────────────────────────────
def _wm_bool(x) -> bool:
    try:
        if isinstance(x, str):
            return x.strip().lower() in ("1", "true", "y", "yes", "t")
        return bool(x)
    except Exception:
        return False

def _wm_series_bool(s: pd.Series) -> pd.Series:
    return s.fillna(False).astype(bool)






def _grade_rank_map():
    return {
        "S+": 9, "S": 8,
        "A+": 7, "A": 6, "A-": 5,
        "B+": 4, "B": 3,
        "C": 2, "D": 1,
    }

def _clamp_grade_down(current_grade: str, target_grade: str) -> str:
    rank = _grade_rank_map()
    cur = str(current_grade or "C").strip()
    tgt = str(target_grade or "C").strip()
    if rank.get(cur, 0) > rank.get(tgt, 0):
        return tgt
    return cur

def _is_largecap_blue_guard_target(cur: dict, row: dict) -> bool:
    idx_label = str(row.get("index_label", "") or row.get("유니버스태그", "") or row.get("universe_tag", "") or "")
    marcap = 0.0
    try:
        marcap = float(row.get("marcap") or row.get("market_cap") or row.get("시가총액") or 0)
    except Exception:
        marcap = 0.0
    return ("코스피200" in idx_label) or ("KOSPI200" in idx_label) or (marcap >= 5_000_000_000_000)

def _largecap_blue_confirm_score(cur: dict) -> int:
    score = 0
    close = float(cur.get("close", 0) or 0)
    prev_box_high10 = float(cur.get("prev_box_high10", 0) or 0)
    volume = float(cur.get("volume", 0) or 0)
    vol_ma20 = float(cur.get("vol_ma20", 0) or 0)
    rsi = float(cur.get("rsi", 0) or 0)
    adx = float(cur.get("adx", 0) or 0)
    adx_prev = float(cur.get("adx_prev", 0) or 0)
    obv_slope5 = float(cur.get("obv_slope5", 0) or 0)
    obv_rising = bool(cur.get("obv_rising", False))

    if prev_box_high10 > 0 and close >= prev_box_high10 * 0.99:
        score += 1
    if vol_ma20 > 0 and volume >= vol_ma20 * 1.05:
        score += 1
    if rsi >= 54.0:
        score += 1
    if obv_slope5 > 0 or obv_rising:
        score += 1
    if adx >= 16.0 or adx > adx_prev:
        score += 1
    return score

def build_watermelon_state_bundle(df: pd.DataFrame) -> dict:
    """
    red onset(붉은 보조지표 시작점) 기반 수박/파란점 엔진.
    핵심:
      - 초입수박: 실제 박스권이 있고, 아직 과열되지 않았으며, 아직 빨강이 시작되기 전 준비 상태
      - Blue-1: 초입 박스에서 '첫 red onset'이 발생하는 순간(단기)
      - 눌림수박: Blue-1 이후 건강한 눌림 박스가 다시 만들어진 상태
      - Blue-2: 눌림 박스 이후 '두 번째 red onset'이 발생하는 순간(스윙)
      - 후행수박: 이미 많이 진행된 뒤의 늦은 상태(신규매수보다 경계/관리)
    """
    empty_bundle = {
        "wm_base_score": 0,
        "wm_pocket_score": 0,
        "wm_attack_score": 0,
        "wm_blue_score": 0,
        "wm_blue1_score": 0,
        "wm_blue2_score": 0,
        "wm_pocket_raw": False,
        "wm_pocket_hold": False,
        "wm_attack_raw": False,
        "wm_attack_hold": False,
        "wm_blue_raw": False,
        "wm_blue_hold": False,
        "wm_intro": False,
        "wm_pullback": False,
        "wm_late": False,
        "wm_blue1_raw": False,
        "wm_blue1_hold": False,
        "wm_blue2_raw": False,
        "wm_blue2_hold": False,
        "wm_state_green": False,
        "wm_state_red": False,
        "wm_state_blue": False,
        "wm_final_state": "",
        "wm_state_name": "",
        "wm_state_grade": "없음",
        "wm_state_tags": [],
        "wm_state_detail": {"ok": False, "error": "봉수 부족"},
    }
    if df is None or df.empty or len(df) < 80:
        return empty_bundle

    def _upper_wick_ratio(row) -> float:
        try:
            o = safe_float(row.get("Open", 0))
            h = safe_float(row.get("High", 0))
            l = safe_float(row.get("Low", 0))
            c = safe_float(row.get("Close", 0))
            rng = max(h - l, 1e-9)
            upper = max(h - max(o, c), 0)
            return upper / rng * 100.0
        except Exception:
            return 999.0

    def _metrics(sub: pd.DataFrame) -> dict:
        r = sub.iloc[-1]

        close = safe_float(r.get("Close", 0))
        open_ = safe_float(r.get("Open", 0))
        high = safe_float(r.get("High", 0))
        low = safe_float(r.get("Low", 0))
        volume = safe_float(r.get("Volume", 0))
        ma5 = safe_float(r.get("MA5", 0))
        ma20 = safe_float(r.get("MA20", 0))
        ma60 = safe_float(r.get("MA60", 0))
        ma112 = safe_float(r.get("MA112", 0))
        obv = safe_float(r.get("OBV", 0))
        obv_ma10 = safe_float(r.get("OBV_MA10", 0))
        rsi = safe_float(r.get("RSI", 50), 50)

        recent120 = sub.tail(120)
        recent30 = sub.tail(30)
        recent25 = sub.tail(25)
        recent20 = sub.tail(20)
        recent15 = sub.tail(15)
        recent10 = sub.tail(10)
        recent5 = sub.tail(5)

        box_high25 = safe_float(recent25["High"].max(), 0) if len(recent25) else 0
        box_low25 = safe_float(recent25["Low"].min(), 0) if len(recent25) else 0
        prev_box_high25 = safe_float(recent25["High"].iloc[:-1].max(), 0) if len(recent25) >= 2 else box_high25
        prev_box_high20 = safe_float(recent20["High"].iloc[:-1].max(), 0) if len(recent20) >= 2 else safe_float(recent20["High"].max(), 0)
        prev_box_high10 = safe_float(recent10["High"].iloc[:-1].max(), 0) if len(recent10) >= 2 else safe_float(recent10["High"].max(), 0)
        prev_box_high5 = safe_float(recent5["High"].iloc[:-1].max(), 0) if len(recent5) >= 2 else safe_float(recent5["High"].max(), 0)

        low5 = safe_float(recent5["Low"].min(), 0) if len(recent5) else 0
        low10 = safe_float(recent10["Low"].min(), 0) if len(recent10) else 0
        low15 = safe_float(recent15["Low"].min(), 0) if len(recent15) else 0
        low20 = safe_float(recent20["Low"].min(), 0) if len(recent20) else 0

        vol_ma20 = safe_float(recent20["Volume"].mean(), 0) if len(recent20) else 0
        vol_ma5 = safe_float(recent5["Volume"].mean(), 0) if len(recent5) else 0
        amount = close * volume
        amount_ma20 = safe_float((recent20["Close"] * recent20["Volume"]).mean(), 0) if len(recent20) else 0

        box_range_pct25 = ((box_high25 - box_low25) / close * 100.0) if close > 0 and box_high25 > 0 else 999.0
        pullback_pct25 = ((box_high25 - close) / box_high25 * 100.0) if box_high25 > 0 else 0.0

        ret7 = ((close / safe_float(sub["Close"].iloc[-8], 0)) - 1.0) * 100.0 if len(sub) >= 8 and safe_float(sub["Close"].iloc[-8], 0) > 0 else 0.0
        ret15 = ((close / safe_float(sub["Close"].iloc[-16], 0)) - 1.0) * 100.0 if len(sub) >= 16 and safe_float(sub["Close"].iloc[-16], 0) > 0 else 0.0
        ret20 = ((close / safe_float(sub["Close"].iloc[-21], 0)) - 1.0) * 100.0 if len(sub) >= 21 and safe_float(sub["Close"].iloc[-21], 0) > 0 else 0.0

        daychg10 = (((recent10["Close"] / recent10["Close"].shift(1)) - 1.0) * 100.0).replace([np.inf, -np.inf], np.nan).fillna(0) if len(recent10) else pd.Series(dtype=float)
        max_day_up10 = safe_float(daychg10.max(), 0) if len(daychg10) else 0

        cond_base_1 = bool((((recent120["High"] / recent120["Close"].shift(1)) - 1.0) * 100 >= 8).fillna(False).any()) if {"High", "Close"} <= set(recent120.columns) else False
        cond_base_2 = bool((recent120["Volume"] > recent120["Volume"].rolling(20, min_periods=5).mean() * 1.8).fillna(False).any()) if "Volume" in recent120.columns else False
        cond_base_3 = (close >= ma60 * 0.98) if ma60 > 0 else False
        cond_base_4 = (ma20 >= ma60 * 0.96) if ma20 > 0 and ma60 > 0 else False
        cond_base_5 = (obv >= obv_ma10) if obv_ma10 != 0 else False
        base_score = int(cond_base_1) + int(cond_base_2) + int(cond_base_3) + int(cond_base_4) + int(cond_base_5)

        cond_pocket_1 = 6.0 <= box_range_pct25 <= 18.0
        cond_pocket_2 = (close >= box_low25 * 1.03 and close <= prev_box_high25 * 1.01) if box_low25 > 0 and prev_box_high25 > 0 else False
        cond_pocket_3 = (low5 >= low10 * 0.985) if low10 > 0 else False
        cond_pocket_4 = (vol_ma5 <= vol_ma20 * 1.05) if vol_ma20 > 0 else False
        cond_pocket_5 = ((close >= ma20 * 0.97) if ma20 > 0 else False) or ((close >= ma60 * 0.98) if ma60 > 0 else False)
        pocket_score = int(cond_pocket_1) + int(cond_pocket_2) + int(cond_pocket_3) + int(cond_pocket_4) + int(cond_pocket_5)

        cond_attack_1 = (obv >= obv_ma10) if obv_ma10 != 0 else False
        cond_attack_2 = (close >= ma20 * 0.99) if ma20 > 0 else False
        cond_attack_3 = (ma5 >= ma20 * 0.995) if ma5 > 0 and ma20 > 0 else False
        cond_attack_4 = (volume >= vol_ma20 * 1.05) if vol_ma20 > 0 else False
        cond_attack_5 = (amount >= amount_ma20 * 1.05) if amount_ma20 > 0 else False
        attack_score = int(cond_attack_1) + int(cond_attack_2) + int(cond_attack_3) + int(cond_attack_4) + int(cond_attack_5)

        change_ready = (
            (attack_score >= 3)
            and ((volume >= vol_ma20 * 1.05) if vol_ma20 > 0 else False)
            and ((amount >= amount_ma20 * 1.05) if amount_ma20 > 0 else False)
            and (_upper_wick_ratio(r) <= 40.0)
            and (rsi < 72.0)
        )

        box_ready = (base_score >= 2) and (pocket_score >= 4)

        return {
            "close": close, "open": open_, "high": high, "low": low, "volume": volume,
            "ma5": ma5, "ma20": ma20, "ma60": ma60, "ma112": ma112,
            "obv": obv, "obv_ma10": obv_ma10, "rsi": rsi,
            "vol_ma20": vol_ma20, "vol_ma5": vol_ma5,
            "amount": amount, "amount_ma20": amount_ma20,
            "box_high25": box_high25, "box_low25": box_low25,
            "prev_box_high25": prev_box_high25, "prev_box_high20": prev_box_high20,
            "prev_box_high10": prev_box_high10, "prev_box_high5": prev_box_high5,
            "low5": low5, "low10": low10, "low15": low15, "low20": low20,
            "box_range_pct25": box_range_pct25, "pullback_pct25": pullback_pct25,
            "ret7": ret7, "ret15": ret15, "ret20": ret20, "max_day_up10": max_day_up10,
            "base_score": base_score, "pocket_score": pocket_score, "attack_score": attack_score,
            "box_ready": box_ready, "change_ready": change_ready,
            "cond_base": [cond_base_1, cond_base_2, cond_base_3, cond_base_4, cond_base_5],
            "cond_pocket": [cond_pocket_1, cond_pocket_2, cond_pocket_3, cond_pocket_4, cond_pocket_5],
            "cond_attack": [cond_attack_1, cond_attack_2, cond_attack_3, cond_attack_4, cond_attack_5],
        }

    start_idx = max(80, len(df) - 60)
    hist = []
    red_state_hist = []
    red_onset_hist = []
    blue1_onset_hist = []
    pullback_hist = []
    blue2_onset_hist = []

    for i in range(start_idx, len(df)):
        sub = df.iloc[:i+1]
        m = _metrics(sub)

        had_red_onset_recent = sum(1 for x in red_onset_hist[-20:] if x) >= 1
        had_blue1_recent = sum(1 for x in blue1_onset_hist[-20:] if x) >= 1
        had_pullback_recent = sum(1 for x in pullback_hist[-12:] if x) >= 1
        had_blue2_recent = sum(1 for x in blue2_onset_hist[-25:] if x) >= 1

        # ✅ late 완화: 단순히 박스 고점 근처라는 이유만으로 후행수박으로 밀어내지 않음
        late = (
            (m["ret20"] >= 26.0)
            or (m["max_day_up10"] >= 14.0)
            or (
                ((m["close"] >= m["prev_box_high25"] * 1.015) if m["prev_box_high25"] > 0 else False)
                and (m["ret15"] >= 12.0)
            )
            or had_blue2_recent
        )

        intro_box_range_ok = bool(5.0 <= m["box_range_pct25"] <= 32.0)
        intro_attack_band_ok = bool(2 <= m["attack_score"] <= 5)
        intro_ret7_ok = bool(m["ret7"] <= 14.0)
        intro_ret15_ok = bool(m["ret15"] <= 18.0)
        intro_ret20_ok = bool(m["ret20"] <= 17.0)
        intro_dayup_ok = bool(m["max_day_up10"] <= 10.0)
        intro_top_near_ok = bool((m["close"] <= m["prev_box_high25"] * 1.00) if m["prev_box_high25"] > 0 else True)
        intro_vol_calm_ok = bool((m["volume"] <= m["vol_ma20"] * 1.80) if m["vol_ma20"] > 0 else True)
        intro_no_prior_blue1_ok = bool(not had_blue1_recent)
        intro_no_prior_blue2_ok = bool(not had_blue2_recent)
        intro_not_late_ok = bool(not late)

        # ✅ intro_box를 전부 AND가 아니라 점수형으로 완화
        intro_optional_score = sum([
            intro_ret7_ok,
            intro_ret15_ok,
            intro_ret20_ok,
            intro_dayup_ok,
            intro_top_near_ok,
            intro_vol_calm_ok,
            intro_no_prior_blue1_ok,
            intro_no_prior_blue2_ok,
            intro_not_late_ok,
        ])

        intro_box_base_ok = bool(
            m["box_ready"]
            or (
                intro_box_range_ok
                and intro_top_near_ok
                and intro_vol_calm_ok
                and intro_optional_score >= 8
            )
        )

        intro_box_ready = (
            intro_box_base_ok
            and intro_box_range_ok
            and intro_attack_band_ok
            and intro_optional_score >= 6
        )

        change_relaxed_1 = bool(
            m["change_ready"]
            or (
                intro_box_ready
                and ((m["close"] >= m["ma20"] * 0.992) if m["ma20"] > 0 else False)
                and ((m["ma5"] >= m["ma20"] * 0.995) if m["ma5"] > 0 and m["ma20"] > 0 else False)
            )
        )

        red_state_raw = (
            intro_box_ready
            and change_relaxed_1
            and ((m["close"] >= m["ma20"] * 0.985) if m["ma20"] > 0 else False)
            and ((m["ma5"] >= m["ma20"] * 0.985) if m["ma5"] > 0 and m["ma20"] > 0 else False)
            and ((m["close"] >= m["prev_box_high10"] * 0.970) if m["prev_box_high10"] > 0 else False)
            and not late
        )
        prev_red_state = red_state_hist[-1] if red_state_hist else False
        red_onset = bool(red_state_raw and (not prev_red_state))

        # ✅ Blue-1 완화: 초기 신호가 아예 안 뜨는 문제를 줄임
        blue1_onset = (
            red_onset
            and intro_box_ready
            and (m["ret7"] <= 11.0)
            and (m["ret15"] <= 15.0)
            and (m["ret20"] <= 17.0)
            and ((m["close"] <= m["prev_box_high25"] * 1.03) if m["prev_box_high25"] > 0 else True)
            and ((m["volume"] >= m["vol_ma20"] * 0.90) if m["vol_ma20"] > 0 else True)
            and not late
        )

        pullback_box = (
            had_blue1_recent
            and not late
            and (2.0 <= m["pullback_pct25"] <= 15.0)
            and (((m["close"] >= m["ma20"] * 0.97) if m["ma20"] > 0 else False) or ((m["close"] >= m["ma60"] * 0.98) if m["ma60"] > 0 else False))
            and ((m["vol_ma5"] <= m["vol_ma20"] * 1.10) if m["vol_ma20"] > 0 else False)
            and ((m["close"] < m["box_high25"] * 0.995) if m["box_high25"] > 0 else False)
            and (m["low5"] > m["low20"] * 1.00 if m["low20"] > 0 else False)
            and not red_state_raw
        )

        # Blue-1 이전이라도, 한 번 움직인 뒤 건강하게 눌리며 재정비되는 박스는 눌림수박 후보로 인정
        pre_pullback_box = (
            (not had_blue1_recent)
            and not late
            and (2.0 <= m["pullback_pct25"] <= 15.0)
            and (m["box_range_pct25"] <= 26.0)
            and (m["ret20"] <= 17.0)
            and (m["max_day_up10"] <= 10.0)
            and (((m["close"] >= m["ma20"] * 0.98) if m["ma20"] > 0 else False) or ((m["close"] >= m["ma60"] * 0.99) if m["ma60"] > 0 else False))
            and ((m["vol_ma5"] <= m["vol_ma20"] * 1.15) if m["vol_ma20"] > 0 else False)
            and ((m["close"] < m["box_high25"] * 0.996) if m["box_high25"] > 0 else False)
            and (m["low5"] > m["low20"] * 0.995 if m["low20"] > 0 else False)
            and not red_state_raw
        )

        change_relaxed_2 = bool(
            m["change_ready"]
            or (
                ((m["close"] >= m["ma20"] * 0.992) if m["ma20"] > 0 else False)
                and ((m["ma5"] >= m["ma20"] * 0.995) if m["ma20"] > 0 and m["ma5"] > 0 else False)
            )
        )

        red2_pullback_ok = bool(pullback_box or pre_pullback_box)
        red2_change_ok = bool(change_relaxed_2)
        red2_close_ma20_ok = bool((m["close"] >= m["ma20"] * 0.975) if m["ma20"] > 0 else False)
        red2_ma5_ma20_ok = bool((m["ma5"] >= m["ma20"] * 0.988) if m["ma20"] > 0 and m["ma5"] > 0 else False)
        red2_prevbox_ok = bool((m["close"] >= m["prev_box_high10"] * 0.965) if m["prev_box_high10"] > 0 else False)
        red2_vol_ok = bool((m["volume"] >= m["vol_ma20"] * 0.78) if m["vol_ma20"] > 0 else True)
        red2_candle_ok = bool(
            ((m["close"] >= m["open"] * 0.995) if m.get("open", 0) > 0 else True)
            or (m["close"] >= m.get("prev_close", 0))
        )
        red2_not_late_ok = bool(not late)

        # 핵심 구조: m520 또는 pbox 중 하나만 살아도 재점화 예비로 인정
        red2_structure_ok = bool(
            red2_close_ma20_ok
            and red2_vol_ok
            and red2_not_late_ok
            and (red2_ma5_ma20_ok or red2_prevbox_ok)
        )

        # 완화 구조: 5일선 회복 + 준양봉이면 pbox 부족도 예비 인정
        red2_soft_ok = bool(
            red2_close_ma20_ok
            and red2_vol_ok
            and red2_not_late_ok
            and red2_candle_ok
            and ((m["close"] >= m["ma5"]) if m["ma5"] > 0 else False)
        )

        red_state_raw_2 = (
            red2_pullback_ok
            and red2_change_ok
            and (red2_structure_ok or red2_soft_ok)
        )

        blue2_prev_clear_ok = bool((not prev_red_state) or red2_soft_ok)
        blue2_context_ok = bool(
            (had_blue1_recent and had_pullback_recent)
            or pre_pullback_box
            or (pullback_box and (3.0 <= m["pullback_pct25"] <= 15.0))
            or (pullback_box and (m["close"] >= m["ma5"] if m["ma5"] > 0 else False))
        )
        blue2_vol2_ok = bool((m["volume"] >= m["vol_ma20"] * 0.78) if m["vol_ma20"] > 0 else True)

        # ✅ Blue-2 정밀 보정: m520/pbox/candle 병목을 완화해 예비 재점화까지는 통과 허용
        blue2_onset = (
            red_state_raw_2
            and blue2_prev_clear_ok
            and blue2_context_ok
            and blue2_vol2_ok
            and not late
        )

        blue2_strong = bool(
            blue2_onset
            and red2_structure_ok
            and (
                red2_prevbox_ok
                or red2_ma5_ma20_ok
            )
        )
        blue2_preview = bool(
            blue2_onset
            and (not blue2_strong)
            and red2_soft_ok
        )

        # final state: onset를 우선, 그 다음 박스 준비 상태
        final_state = ""
        if late:
            final_state = "후행수박"
        elif blue2_strong:
            final_state = "Blue-2스윙"
        elif blue2_preview:
            final_state = "Blue-2예비"
        elif (pullback_box or pre_pullback_box):
            final_state = "눌림수박"
        elif blue1_onset:
            final_state = "Blue-1단기"
        elif intro_box_ready:
            final_state = "초입수박"

        pocket_raw = final_state in ("초입수박", "눌림수박")
        attack_raw = final_state in ("Blue-1단기", "Blue-2스윙", "Blue-2예비")

        hist.append({
            **m,
            "intro_box_ready": intro_box_ready,
            "red_state_raw": red_state_raw,
            "red_onset": red_onset,
            "blue1_onset": blue1_onset,
            "pullback_box": (pullback_box or pre_pullback_box),
            "red_state_raw_2": red_state_raw_2,
            "blue2_onset": blue2_onset,
            "blue2_strong": blue2_strong,
            "blue2_preview": blue2_preview,
            "late": late,
            "red2_pullback_ok": red2_pullback_ok,
            "red2_change_ok": red2_change_ok,
            "red2_close_ma20_ok": red2_close_ma20_ok,
            "red2_ma5_ma20_ok": red2_ma5_ma20_ok,
            "red2_prevbox_ok": red2_prevbox_ok,
            "red2_vol_ok": red2_vol_ok,
            "red2_candle_ok": red2_candle_ok,
            "red2_not_late_ok": red2_not_late_ok,
            "red2_structure_ok": red2_structure_ok,
            "red2_soft_ok": red2_soft_ok,
            "blue2_prev_clear_ok": blue2_prev_clear_ok,
            "blue2_context_ok": blue2_context_ok,
            "blue2_vol2_ok": blue2_vol2_ok,
            "intro_box_range_ok": intro_box_range_ok,
            "intro_attack_band_ok": intro_attack_band_ok,
            "intro_ret7_ok": intro_ret7_ok,
            "intro_ret15_ok": intro_ret15_ok,
            "intro_ret20_ok": intro_ret20_ok,
            "intro_dayup_ok": intro_dayup_ok,
            "intro_top_near_ok": intro_top_near_ok,
            "intro_vol_calm_ok": intro_vol_calm_ok,
            "intro_no_prior_blue1_ok": intro_no_prior_blue1_ok,
            "intro_no_prior_blue2_ok": intro_no_prior_blue2_ok,
            "intro_not_late_ok": intro_not_late_ok,
            "pocket_raw": pocket_raw,
            "pocket_hold": pocket_raw,
            "attack_raw": attack_raw,
            "attack_hold": attack_raw,
            "intro": final_state == "초입수박",
            "pullback": final_state == "눌림수박",
            "blue1_raw": blue1_onset,
            "blue1_hold": final_state == "Blue-1단기",
            "blue2_raw": blue2_onset,
            "blue2_hold": final_state == "Blue-2스윙",
            "final_state": final_state,
        })
        red_state_hist.append(bool(red_state_raw or red_state_raw_2))
        red_onset_hist.append(bool(red_onset or blue2_onset))
        blue1_onset_hist.append(bool(blue1_onset))
        pullback_hist.append(bool(pullback_box))
        blue2_onset_hist.append(bool(blue2_onset))

    cur = hist[-1]
    final_state = cur.get("final_state", "")

    wm_state_green = final_state in ("초입수박", "눌림수박")
    wm_state_red = final_state in ("Blue-1단기", "Blue-2스윙")
    wm_state_blue = wm_state_red

    if final_state == "초입수박":
        tags = ["🟢초입수박"]
        state_name = "초입수박"
    elif final_state == "눌림수박":
        tags = ["🟩눌림수박"]
        state_name = "눌림수박"
    elif final_state == "후행수박":
        tags = ["🟠후행수박"]
        state_name = "후행수박"
    elif final_state == "Blue-1단기":
        tags = ["🔵Blue-1단기", "🍉재점화공격"]
        state_name = "Blue-1단기"
    elif final_state == "Blue-2스윙":
        tags = ["🔷Blue-2스윙", "🍉재점화공격"]
        state_name = "Blue-2스윙"
    elif final_state == "Blue-2예비":
        tags = ["🔹Blue-2예비", "🍉재점화예비"]
        state_name = "Blue-2예비"
    else:
        tags = []
        state_name = "없음"

    if final_state == "Blue-1단기" and _is_largecap_blue_guard_target(cur, row):
        if blue_confirm >= 4:
            if "🧢대형주확정" not in tags:
                tags.append("🧢대형주확정")
        elif blue_confirm >= 2:
            tags = [t for t in tags if "🍉재점화공격" not in t]
            if "🔵Blue-1확인중" not in tags:
                tags.append("🔵Blue-1확인중")
        else:
            tags = [t for t in tags if "🍉재점화공격" not in t]
            if "🔵Blue-1예비" not in tags:
                tags.append("🔵Blue-1예비")

    wm_blue1_score = int(cur["intro_box_ready"]) + int(cur["change_ready"]) + int(cur["red_onset"]) + int(cur["blue1_onset"]) + int(cur["ret7"] <= 7.0) + int(cur["ret15"] <= 12.0)
    wm_blue2_score = int(cur["pullback_box"]) + int(cur["change_ready"]) + int(cur["blue2_onset"]) + int(3.0 <= cur["pullback_pct25"] <= 14.0) + int(cur["rsi"] < 71.0) + int(cur["volume"] >= cur["vol_ma20"] * 1.08 if cur["vol_ma20"] > 0 else False)
    wm_blue_score = max(wm_blue1_score, wm_blue2_score)

    score_sum = int(cur["base_score"] + cur["pocket_score"] + cur["attack_score"])
    if final_state == "Blue-1단기" and score_sum + wm_blue1_score >= 13:
        grade = "A+"
    elif final_state == "Blue-2스윙" and score_sum + wm_blue2_score >= 11:
        grade = "A"
    elif final_state == "Blue-2예비":
        grade = "B+"
    elif final_state == "후행수박":
        grade = "B"
    elif final_state in ("초입수박", "눌림수박"):
        grade = "C"
    else:
        grade = "없음"

    # ✅ 대형주 Blue-1 과열 보정
    blue_confirm = -1
    if final_state == "Blue-1단기" and _is_largecap_blue_guard_target(cur, row):
        blue_confirm = _largecap_blue_confirm_score(cur)
        if blue_confirm >= 4:
            pass
        elif blue_confirm >= 2:
            grade = _clamp_grade_down(grade, "A")
        else:
            grade = _clamp_grade_down(grade, "B+")

    detail = {
        "ok": True,
        "score_sum": score_sum,
        "ret7": round(cur["ret7"], 2),
        "ret15": round(cur["ret15"], 2),
        "ret20": round(cur["ret20"], 2),
        "pullback_pct25": round(cur["pullback_pct25"], 2),
        "box_range_pct25": round(cur["box_range_pct25"], 2),
        "max_day_up10": round(cur["max_day_up10"], 2),
        "intro_box_ready": bool(cur["intro_box_ready"]),
        "change_ready": bool(cur["change_ready"]),
        "red_state_raw": bool(cur["red_state_raw"]),
        "red_onset": bool(cur["red_onset"]),
        "blue1_onset": bool(cur["blue1_onset"]),
        "pullback_box": bool(cur["pullback_box"]),
        "red_state_raw_2": bool(cur["red_state_raw_2"]),
        "blue2_onset": bool(cur["blue2_onset"]),
        "blue2_strong": bool(cur.get("blue2_strong", False)),
        "blue2_preview": bool(cur.get("blue2_preview", False)),
        "blue_confirm": int(blue_confirm),
        "late": bool(cur["late"]),
        "intro_box_range_ok": bool(cur.get("intro_box_range_ok", False)),
        "intro_attack_band_ok": bool(cur.get("intro_attack_band_ok", False)),
        "intro_ret7_ok": bool(cur.get("intro_ret7_ok", False)),
        "intro_ret15_ok": bool(cur.get("intro_ret15_ok", False)),
        "intro_ret20_ok": bool(cur.get("intro_ret20_ok", False)),
        "intro_dayup_ok": bool(cur.get("intro_dayup_ok", False)),
        "intro_top_near_ok": bool(cur.get("intro_top_near_ok", False)),
        "intro_vol_calm_ok": bool(cur.get("intro_vol_calm_ok", False)),
        "intro_no_prior_blue1_ok": bool(cur.get("intro_no_prior_blue1_ok", False)),
        "intro_no_prior_blue2_ok": bool(cur.get("intro_no_prior_blue2_ok", False)),
        "intro_not_late_ok": bool(cur.get("intro_not_late_ok", False)),
    }

    return {
        "wm_base_score": int(cur["base_score"]),
        "wm_pocket_score": int(cur["pocket_score"]),
        "wm_attack_score": int(cur["attack_score"]),
        "wm_blue_score": int(wm_blue_score),
        "wm_blue1_score": int(wm_blue1_score),
        "wm_blue2_score": int(wm_blue2_score),
        "wm_pocket_raw": bool(cur["pocket_raw"]),
        "wm_pocket_hold": bool(cur["pocket_hold"]),
        "wm_attack_raw": bool(cur["attack_raw"]),
        "wm_attack_hold": bool(cur["attack_hold"]),
        "wm_blue_raw": bool(cur["blue1_raw"] or cur["blue2_raw"]),
        "wm_blue_hold": bool(cur["blue1_hold"] or cur["blue2_hold"]),
        "wm_final_state": final_state,
        "wm_intro": bool(final_state == "초입수박"),
        "wm_pullback": bool(final_state == "눌림수박"),
        "wm_late": bool(final_state == "후행수박"),
        "wm_blue1_raw": bool(cur["blue1_raw"]),
        "wm_blue1_hold": bool(final_state == "Blue-1단기"),
        "wm_blue2_raw": bool(cur["blue2_raw"]),
        "wm_blue2_hold": bool(final_state == "Blue-2스윙"),
        "wm_blue2_preview_hold": bool(final_state == "Blue-2예비"),
        "wm_state_green": bool(wm_state_green),
        "wm_state_red": bool(wm_state_red),
        "wm_state_blue": bool(wm_state_blue),
        "wm_state_name": state_name,
        "wm_state_grade": grade,
        "wm_debug_intro_box_ready": bool(cur["intro_box_ready"]),
        "wm_debug_change_ready": bool(cur["change_ready"]),
        "wm_debug_red_state_raw": bool(cur["red_state_raw"]),
        "wm_debug_red_onset": bool(cur["red_onset"]),
        "wm_debug_blue1_onset": bool(cur["blue1_onset"]),
        "wm_debug_pullback_box": bool(cur["pullback_box"]),
        "wm_debug_red_state_raw_2": bool(cur["red_state_raw_2"]),
        "wm_debug_blue2_onset": bool(cur["blue2_onset"]),
        "wm_debug_blue2_strong": bool(cur.get("blue2_strong", False)),
        "wm_debug_blue2_preview": bool(cur.get("blue2_preview", False)),
        "wm_debug_late": bool(cur["late"]),
        "wm_debug_red2_pullback_ok": bool(cur.get("red2_pullback_ok", False)),
        "wm_debug_red2_change_ok": bool(cur.get("red2_change_ok", False)),
        "wm_debug_red2_close_ma20_ok": bool(cur.get("red2_close_ma20_ok", False)),
        "wm_debug_red2_ma5_ma20_ok": bool(cur.get("red2_ma5_ma20_ok", False)),
        "wm_debug_red2_prevbox_ok": bool(cur.get("red2_prevbox_ok", False)),
        "wm_debug_red2_vol_ok": bool(cur.get("red2_vol_ok", False)),
        "wm_debug_red2_candle_ok": bool(cur.get("red2_candle_ok", False)),
        "wm_debug_red2_not_late_ok": bool(cur.get("red2_not_late_ok", False)),
        "wm_debug_red2_structure_ok": bool(cur.get("red2_structure_ok", False)),
        "wm_debug_red2_soft_ok": bool(cur.get("red2_soft_ok", False)),
        "wm_debug_blue2_prev_clear_ok": bool(cur.get("blue2_prev_clear_ok", False)),
        "wm_debug_blue2_context_ok": bool(cur.get("blue2_context_ok", False)),
        "wm_debug_blue2_vol2_ok": bool(cur.get("blue2_vol2_ok", False)),
        "wm_debug_intro_box_range_ok": bool(cur.get("intro_box_range_ok", False)),
        "wm_debug_intro_attack_band_ok": bool(cur.get("intro_attack_band_ok", False)),
        "wm_debug_intro_ret7_ok": bool(cur.get("intro_ret7_ok", False)),
        "wm_debug_intro_ret15_ok": bool(cur.get("intro_ret15_ok", False)),
        "wm_debug_intro_ret20_ok": bool(cur.get("intro_ret20_ok", False)),
        "wm_debug_intro_dayup_ok": bool(cur.get("intro_dayup_ok", False)),
        "wm_debug_intro_top_near_ok": bool(cur.get("intro_top_near_ok", False)),
        "wm_debug_intro_vol_calm_ok": bool(cur.get("intro_vol_calm_ok", False)),
        "wm_debug_intro_no_prior_blue1_ok": bool(cur.get("intro_no_prior_blue1_ok", False)),
        "wm_debug_intro_no_prior_blue2_ok": bool(cur.get("intro_no_prior_blue2_ok", False)),
        "wm_debug_intro_not_late_ok": bool(cur.get("intro_not_late_ok", False)),
        "wm_state_tags": tags,
        "wm_state_detail": detail,
    }


def build_watermelon_state_top5(df: pd.DataFrame):
    """
    전종목 스캔 결과에서 수박상태 / 단계 분류 / Blue-1 / Blue-2 / 단테 / 돌파 TOP5 추출
    반환:
      - green_df, red_df, blue_df
      - intro_df, pullback_df, late_df, blue1_df, blue2_df
      - dante_pick_df, dante_watch_df, dante_ex_df
      - breakout_pick_df, breakout_watch_df
    """
    if df is None or df.empty:
        empty = pd.DataFrame()
        return (
            empty, empty, empty,
            empty, empty, empty, empty, empty,
            empty, empty, empty,
            empty, empty,
        )

    work = df.copy()
    if "수박최종상태" not in work.columns:
        work["수박최종상태"] = work.get("수박상태명", "")

    def _sort(df_in: pd.DataFrame, cols: list, ascending=None) -> pd.DataFrame:
        if df_in is None or df_in.empty:
            return pd.DataFrame()
        sort_cols = [c for c in cols if c in df_in.columns]
        if not sort_cols:
            return df_in.head(5).reset_index(drop=True)
        if ascending is None:
            ascending = [False] * len(sort_cols)
        else:
            try:
                ascending = list(ascending)
            except Exception:
                ascending = [False] * len(sort_cols)
            if len(ascending) < len(sort_cols):
                ascending = ascending + [False] * (len(sort_cols) - len(ascending))
            elif len(ascending) > len(sort_cols):
                ascending = ascending[:len(sort_cols)]
        return df_in.sort_values(by=sort_cols, ascending=ascending).head(5).reset_index(drop=True)

    intro_df = _sort(work[work["수박최종상태"] == "초입수박"].copy(), ["수박포켓점수", "수박기반점수", "안전점수", "N점수"])
    pullback_df = _sort(work[work["수박최종상태"] == "눌림수박"].copy(), ["수박포켓점수", "수박기반점수", "안전점수", "N점수"])
    late_df = _sort(work[work["수박최종상태"] == "후행수박"].copy(), ["수박공격점수", "수박기반점수", "N점수"])
    blue1_df = _sort(work[work["수박최종상태"] == "Blue-1단기"].copy(), ["파란점선1단기점수", "수박공격점수", "안전점수", "N점수"])
    blue2_df = _sort(work[work["수박최종상태"] == "Blue-2스윙"].copy(), ["파란점선2스윙점수", "수박포켓점수", "안전점수", "N점수"])

    dante_work = compute_dante_mode_fields(work)
    breakout_work = compute_breakout_mode_fields(dante_work)
    preempt_state_col = "선취상태" if "선취상태" in dante_work.columns else "단테상태"
    preempt_score_col = "선취점수" if "선취점수" in dante_work.columns else "단테점수"
    dante_pick_df = _sort(dante_work[dante_work[preempt_state_col] == "선취형"].copy(), [preempt_score_col, "수박포켓점수", "안전점수", "N점수"])
    dante_watch_df = _sort(dante_work[dante_work[preempt_state_col] == "선취관찰형"].copy(), [preempt_score_col, "수박포켓점수", "안전점수", "N점수"])
    dante_ex_df = _sort(dante_work[dante_work[preempt_state_col] == "선취제외형"].copy(), [preempt_score_col, "수박포켓점수", "안전점수", "N점수"], ascending=[True, False, False, False])
    breakout_pick_df = _sort(breakout_work[breakout_work["돌파상태"] == "흰구름돌파형"].copy(), ["돌파점수", "수박공격점수", "안전점수", "N점수"])
    breakout_watch_df = _sort(breakout_work[breakout_work["돌파상태"] == "돌파관찰형"].copy(), ["돌파점수", "수박공격점수", "안전점수", "N점수"])

    green_df = _sort(work[work["수박최종상태"].isin(["초입수박", "눌림수박"])].copy(), ["수박포켓점수", "수박기반점수", "안전점수", "N점수"])
    red_df = _sort(work[work["수박최종상태"].isin(["Blue-1단기", "Blue-2스윙", "Blue-2예비"])].copy(), ["수박파란점선점수", "수박공격점수", "안전점수", "N점수"])
    blue_df = _sort(work[work["수박최종상태"].isin(["Blue-1단기", "Blue-2스윙"])].copy(), ["수박파란점선점수", "수박공격점수", "안전점수", "N점수"])

    return (
        green_df, red_df, blue_df,
        intro_df, pullback_df, late_df, blue1_df, blue2_df,
        dante_pick_df, dante_watch_df, dante_ex_df,
        breakout_pick_df, breakout_watch_df,
    )



def should_show_wm_debug_alert(
    wm_intro_top5=None,
    wm_pullback_top5=None,
    wm_blue1_top5=None,
    wm_blue2_top5=None,
    wm_late_top5=None,
) -> bool:
    intro_n = len(wm_intro_top5) if wm_intro_top5 is not None else 0
    pullback_n = len(wm_pullback_top5) if wm_pullback_top5 is not None else 0
    blue1_n = len(wm_blue1_top5) if wm_blue1_top5 is not None else 0
    blue2_n = len(wm_blue2_top5) if wm_blue2_top5 is not None else 0
    late_n = len(wm_late_top5) if wm_late_top5 is not None else 0

    if intro_n == 0 and pullback_n == 0:
        return True
    if blue1_n == 0 and blue2_n == 0 and intro_n <= 1:
        return True
    if late_n >= 5 and blue1_n == 0:
        return True
    return False


def build_wm_alert_summary(
    wm_intro_top5=None,
    wm_pullback_top5=None,
    wm_blue1_top5=None,
    wm_blue2_top5=None,
    wm_late_top5=None,
) -> str:
    intro_n = len(wm_intro_top5) if wm_intro_top5 is not None else 0
    pullback_n = len(wm_pullback_top5) if wm_pullback_top5 is not None else 0
    blue1_n = len(wm_blue1_top5) if wm_blue1_top5 is not None else 0
    blue2_n = len(wm_blue2_top5) if wm_blue2_top5 is not None else 0
    late_n = len(wm_late_top5) if wm_late_top5 is not None else 0

    if intro_n == 0 and pullback_n == 0:
        return "⚠ 수박 이상징후: 초입/눌림 후보가 거의 없음"
    if blue1_n == 0 and blue2_n == 0 and intro_n <= 1:
        return "⚠ 수박 이상징후: Blue-1/Blue-2 후보가 비정상적으로 적음"
    if late_n >= 5 and blue1_n == 0:
        return "⚠ 수박 이상징후: 후행 판정 비중이 높고 재점화 후보가 없음"
    return ""


def time_symmetry_bonus_by_state(state: str, time_tag: str) -> float:
    state = str(state or "").strip()
    time_tag = str(time_tag or "").strip()

    strong_states = {"PASS_A", "초입수박", "눌림수박", "Blue-1단기", "Blue-2스윙", "돌파직전"}
    weak_states = {"후행수박", "DROP", "late"}

    if state in weak_states:
        return 0.0
    if state not in strong_states:
        return 0.0

    if "근접" in time_tag:
        return 2.0
    if "예비" in time_tag:
        return 1.0
    return 0.0

def _nearest_time_symmetry(days: int):
    periods = [9, 17, 26, 33, 42]
    if days is None:
        return None, None
    try:
        d = int(days)
    except Exception:
        return None, None
    nearest = min(periods, key=lambda x: abs(d - x))
    gap = abs(d - nearest)
    return nearest, gap

def _time_symmetry_tag(days: int) -> str:
    if days is None:
        return ""
    try:
        d = int(days)
    except Exception:
        return ""
    if d < 0:
        return ""
    nearest, gap = _nearest_time_symmetry(d)
    if nearest is None:
        return ""
    if gap <= 1:
        return f"⏱{nearest}근접"
    elif gap <= 2:
        return f"⏱{nearest}예비"
    return ""

def _time_symmetry_comment(days: int, label: str = "기준봉") -> str:
    if days is None:
        return ""
    try:
        d = int(days)
    except Exception:
        return ""
    if d < 0:
        return ""
    nearest, gap = _nearest_time_symmetry(d)
    if nearest is None:
        return ""
    if gap <= 1:
        return f"{label} 후 {nearest}일 변곡창 근접"
    elif gap <= 2:
        return f"{label} 후 {nearest}일 예비창 접근"
    elif gap <= 4:
        return f"{label} 후 {nearest}일 대칭권 근처"
    return ""

def _safe_parse_dt_local(v):
    try:
        if v is None:
            return None
        x = pd.to_datetime(v, errors="coerce")
        if pd.isna(x):
            return None
        return x.normalize()
    except Exception:
        return None

def _business_days_since_anchor(anchor_date, ref_date=None) -> int:
    a = _safe_parse_dt_local(anchor_date)
    if a is None:
        return -1
    if ref_date is None:
        ref_date = globals().get("TODAY_STR", None)
    r = _safe_parse_dt_local(ref_date)
    if r is None or r < a:
        return -1
    try:
        bdays = pd.bdate_range(a, r)
        return max(len(bdays) - 1, 0)
    except Exception:
        return -1

def _pick_time_sym_anchor(row) -> tuple:
    candidates = [
        ("Blue-1", row.get("blue1_date")),
        ("최근저점", row.get("recent_low_date")),
        ("박스시작", row.get("box_start_date")),
        ("S1", row.get("S1날짜")),
        ("S1", row.get("S1")),
        ("S1", row.get("s1_date")),
    ]
    for label, val in candidates:
        if _safe_parse_dt_local(val) is not None:
            return label, val
    return "", None

def annotate_time_symmetry_df(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or df.empty:
        return df
    work = df.copy()
    days_list, tag_list, comment_list, label_list = [], [], [], []
    for _, row in work.iterrows():
        label, anchor = _pick_time_sym_anchor(row)
        days = _business_days_since_anchor(anchor, globals().get("TODAY_STR", None))
        days_list.append(days)
        label_list.append(label)
        tag_list.append(_time_symmetry_tag(days))
        comment_list.append(_time_symmetry_comment(days, label or "기준봉"))
    work["time_sym_days"] = days_list
    work["time_sym_label"] = label_list
    work["time_sym_tag"] = tag_list
    work["time_sym_comment"] = comment_list

    bonus_list = []
    for _, row in work.iterrows():
        state_name = str(row.get("상태") or row.get("단계") or row.get("final_state") or "").strip()
        bonus_list.append(time_symmetry_bonus_by_state(state_name, row.get("time_sym_tag", "")))
    work["time_sym_bonus"] = bonus_list
    return work

def _ma5r_float(x, default=0.0):
    try:
        return float(x)
    except Exception:
        return default


def _ma5r_upper_wick_pct(open_p, high_p, low_p, close_p):
    try:
        body_high = max(open_p, close_p)
        body = max(abs(close_p - open_p), 1e-6)
        upper = max(high_p - body_high, 0.0)
        return (upper / body) * 100.0
    except Exception:
        return 999.0


def detect_ma5_reclaim_signal(df: pd.DataFrame, i: int) -> dict:
    """
    하락 후 5일선 재안착 탐지
    - 전일 5일선 아래, 당일 5일선 위 재안착
    - 거래량/20일선/양봉/윗꼬리/최근 낙폭을 함께 확인
    """
    empty = {
        "ok": False,
        "score": 0,
        "tag": "",
        "comment": "",
        "reclaim": False,
        "vol_ok": False,
        "near_ma20": False,
        "candle_ok": False,
        "wick_ok": False,
        "drop_ok": False,
        "ma5_rising": False,
    }
    try:
        if df is None or i <= 0 or i >= len(df):
            return empty.copy()

        row = df.iloc[i]
        prev = df.iloc[i - 1]

        close_p = _ma5r_float(row.get("Close", row.get("close", 0)))
        open_p  = _ma5r_float(row.get("Open", row.get("open", 0)))
        high_p  = _ma5r_float(row.get("High", row.get("high", 0)))
        low_p   = _ma5r_float(row.get("Low", row.get("low", 0)))
        vol     = _ma5r_float(row.get("Volume", row.get("volume", 0)))

        prev_close = _ma5r_float(prev.get("Close", prev.get("close", 0)))

        ma5 = _ma5r_float(row.get("MA5", row.get("ma5", 0)))
        ma20 = _ma5r_float(row.get("MA20", row.get("ma20", 0)))
        prev_ma5 = _ma5r_float(prev.get("MA5", prev.get("ma5", 0)))

        vma5 = _ma5r_float(row.get("VMA5", row.get("vol_ma5", 0)))
        vma20 = _ma5r_float(row.get("VMA20", row.get("vol_ma20", 0)))

        if "ret5" in row.index:
            ret5 = _ma5r_float(row.get("ret5", 0))
        elif i >= 5:
            ref_close = _ma5r_float(df.iloc[i - 5].get("Close", 0))
            ret5 = ((close_p / ref_close) - 1.0) * 100.0 if ref_close > 0 else 0.0
        else:
            ret5 = 0.0

        wick_pct = _ma5r_upper_wick_pct(open_p, high_p, low_p, close_p)

        reclaim = (prev_close < prev_ma5 * 0.995) and (close_p >= ma5)
        vol_ok = ((vma5 > 0 and vol >= vma5 * 1.10) or (vma20 > 0 and vol >= vma20 * 0.95))
        near_ma20 = (ma20 > 0 and close_p >= ma20 * 0.98)
        candle_ok = close_p >= open_p
        wick_ok = wick_pct <= 35.0
        drop_ok = (-12.0 <= ret5 <= 3.0)
        ma5_rising = ma5 >= prev_ma5

        score = sum([
            1 if reclaim else 0,
            1 if vol_ok else 0,
            1 if near_ma20 else 0,
            1 if candle_ok else 0,
            1 if wick_ok else 0,
            1 if drop_ok else 0,
            1 if ma5_rising else 0,
        ])

        ok = reclaim and score >= 5

        tag = ""
        comment = ""
        if ok:
            tag = "🔁5일재안착"
            comment = "하락 후 5일선 재안착 + 거래량/캔들 조건 통과"
        elif reclaim:
            tag = "🔁5일재안착예비"
            comment = "5일선은 재안착했지만 거래량·캔들·20일선 확인 필요"

        return {
            "ok": ok,
            "score": int(score),
            "tag": tag,
            "comment": comment,
            "reclaim": bool(reclaim),
            "vol_ok": bool(vol_ok),
            "near_ma20": bool(near_ma20),
            "candle_ok": bool(candle_ok),
            "wick_ok": bool(wick_ok),
            "drop_ok": bool(drop_ok),
            "ma5_rising": bool(ma5_rising),
        }
    except Exception:
        return empty.copy()

def _wc_safe_float(x, default=0.0):
    try:
        return float(x)
    except Exception:
        return default


def _wc_ema(series, span=5):
    try:
        return series.ewm(span=span, adjust=False).mean()
    except Exception:
        return series


def add_white_cloud_candidates(df: pd.DataFrame) -> pd.DataFrame:
    """
    흰색 배경 대체 후보 3종 생성
    A: 중간합성선형  (MA224 ~ EMA((MA112+MA224)/2))
    B: 112 상단밴드형 (MA224 ~ MA112*1.02)
    C: 빠른 리드형    (MA224 ~ EMA(MA112,5)*1.01)
    """
    if df is None or df.empty:
        return df

    work = df.copy()

    if 'MA112' not in work.columns and 'Close' in work.columns:
        work['MA112'] = work['Close'].rolling(112).mean()
    if 'MA224' not in work.columns and 'Close' in work.columns:
        work['MA224'] = work['Close'].rolling(224).mean()

    if 'MA112' not in work.columns or 'MA224' not in work.columns:
        return work

    ma112 = work['MA112']
    ma224 = work['MA224']

    wc_a_mid = (ma112 + ma224) / 2.0
    work['WC_A_TOP'] = _wc_ema(wc_a_mid, span=5)
    work['WC_A_BOT'] = ma224

    work['WC_B_TOP'] = ma112 * 1.02
    work['WC_B_BOT'] = ma224

    work['WC_C_TOP'] = _wc_ema(ma112, span=5) * 1.01
    work['WC_C_BOT'] = ma224

    return work


def detect_white_cloud_state(df: pd.DataFrame, i: int, mode: str = "A") -> dict:
    empty = {
        'below': False,
        'inside': False,
        'above': False,
        'near_lower': False,
        'top': 0.0,
        'bottom': 0.0,
        'tag': '',
        'comment': '',
    }
    try:
        if df is None or i < 0 or i >= len(df):
            return empty.copy()

        row = df.iloc[i]
        close_p = _wc_safe_float(row.get('Close', 0))
        mode = str(mode or 'A').upper().strip()

        if mode == 'A':
            top = _wc_safe_float(row.get('WC_A_TOP', 0))
            bottom = _wc_safe_float(row.get('WC_A_BOT', 0))
        elif mode == 'B':
            top = _wc_safe_float(row.get('WC_B_TOP', 0))
            bottom = _wc_safe_float(row.get('WC_B_BOT', 0))
        else:
            top = _wc_safe_float(row.get('WC_C_TOP', 0))
            bottom = _wc_safe_float(row.get('WC_C_BOT', 0))

        if top <= 0 or bottom <= 0:
            return empty.copy()

        upper = max(top, bottom)
        lower = min(top, bottom)

        below = close_p < lower
        inside = lower <= close_p <= upper
        above = close_p > upper
        near_lower = below and (close_p >= lower * 0.90)

        tag = ''
        comment = ''
        if near_lower:
            tag = f'☁{mode}-아래근접'
            comment = '흰배경 아래 선취 가능 구간'
        elif below:
            tag = f'☁{mode}-아래'
            comment = '장기 저항 아래 구간'
        elif inside:
            tag = f'☁{mode}-안'
            comment = '구름 내부 저항 확인 구간'
        elif above:
            tag = f'☁{mode}-위'
            comment = '이미 장기 저항 위, 추격 주의'

        return {
            'below': bool(below),
            'inside': bool(inside),
            'above': bool(above),
            'near_lower': bool(near_lower),
            'top': round(upper, 2),
            'bottom': round(lower, 2),
            'tag': tag,
            'comment': comment,
        }
    except Exception:
        return empty.copy()


def detect_white_cloud_vote(df: pd.DataFrame, i: int) -> dict:
    a = detect_white_cloud_state(df, i, 'A')
    b = detect_white_cloud_state(df, i, 'B')
    c = detect_white_cloud_state(df, i, 'C')

    below_n = int(a['below']) + int(b['below']) + int(c['below'])
    inside_n = int(a['inside']) + int(b['inside']) + int(c['inside'])
    above_n = int(a['above']) + int(b['above']) + int(c['above'])
    near_n = int(a['near_lower']) + int(b['near_lower']) + int(c['near_lower'])

    state = 'mixed'
    if below_n >= 2:
        state = 'below'
    elif inside_n >= 2:
        state = 'inside'
    elif above_n >= 2:
        state = 'above'

    tag = ''
    comment = ''
    if near_n >= 2:
        tag = '☁아래근접'
        comment = '흰배경 아래 선취 후보'
    elif state == 'below':
        tag = '☁아래'
        comment = '장기 저항 아래 구간'
    elif state == 'inside':
        tag = '☁안'
        comment = '구름 내부 저항 확인 구간'
    elif state == 'above':
        tag = '☁위'
        comment = '이미 장기 저항 위, 추격 주의'
    else:
        tag = '☁혼합'
        comment = '후보별 판정이 엇갈림'

    return {
        'A': a,
        'B': b,
        'C': c,
        'state': state,
        'tag': tag,
        'comment': comment,
        'below_n': below_n,
        'inside_n': inside_n,
        'above_n': above_n,
        'near_n': near_n,
    }

def detect_refined_watermelon_filter(
    df: pd.DataFrame,
    i: int,
    white_cloud_bundle: Optional[dict] = None,
    ma5_reclaim_bundle: Optional[dict] = None,
) -> dict:
    """
    좋은 수박 / 가짜 수박을 가르는 보조 필터
    핵심:
    - 장기이평에서 너무 멀리 이탈하지 않았는가
    - 거래량/재안착/캔들 질이 받쳐주는가
    - 흰구름(장기 저항대) 위치가 과열 구간은 아닌가
    """
    empty = {
        "ok": False,
        "weak": False,
        "caution": False,
        "score": 0,
        "tag": "",
        "comment": "",
        "vol_ok": False,
        "reclaim_ok": False,
        "candle_ok": False,
        "wick_ok": False,
        "long_ok": False,
        "cloud_ok": False,
        "obv_ok": False,
        "hard_fail": False,
    }
    try:
        if df is None or df.empty or i < 0 or i >= len(df):
            return empty.copy()

        row = df.iloc[i]
        prev = df.iloc[i - 1] if i >= 1 else row

        close_p = _ma5r_float(row.get("Close", row.get("close", 0)))
        open_p = _ma5r_float(row.get("Open", row.get("open", 0)))
        high_p = _ma5r_float(row.get("High", row.get("high", 0)))
        vol = _ma5r_float(row.get("Volume", row.get("volume", 0)))
        prev_close = _ma5r_float(prev.get("Close", prev.get("close", 0)))
        prev_vol = _ma5r_float(prev.get("Volume", prev.get("volume", 0)))

        ma5 = _ma5r_float(row.get("MA5", row.get("ma5", 0)))
        ma20 = _ma5r_float(row.get("MA20", row.get("ma20", 0)))
        ma112 = _ma5r_float(row.get("MA112", row.get("ma112", 0)))
        ma224 = _ma5r_float(row.get("MA224", row.get("ma224", 0)))
        vma20 = _ma5r_float(row.get("VMA20", row.get("vol_ma20", 0)))

        wick_pct = _ma5r_upper_wick_pct(open_p, high_p, _ma5r_float(row.get("Low", row.get("low", 0))), close_p)

        obv = _ma5r_float(row.get("OBV", row.get("obv", 0)))
        prev_obv = _ma5r_float(prev.get("OBV", prev.get("obv", 0)))
        obv_slope = _ma5r_float(
            row.get(
                "OBV_Slope",
                row.get(
                    "OBV_SLOPE_5",
                    row.get("obv_slope", row.get("OBV_SLOPE_10", 0)),
                ),
            ),
            0.0,
        )

        long_refs = [x for x in [ma112, ma224] if x > 0]
        long_floor = min(long_refs) if long_refs else 0.0
        long_ceiling = max(long_refs) if long_refs else 0.0

        near_long_ok = True if long_floor <= 0 else (close_p >= long_floor * 0.84)
        not_too_high = True if long_ceiling <= 0 else (close_p <= long_ceiling * 1.10)
        long_ok = bool(near_long_ok and not_too_high)

        vol_ok = bool(
            (vma20 > 0 and vol >= vma20 * 0.85)
            or (prev_vol > 0 and vol >= prev_vol * 0.90)
        )

        reclaim_ok = bool(
            (ma5_reclaim_bundle or {}).get("ok", False)
            or (ma5_reclaim_bundle or {}).get("reclaim", False)
            or ((ma5 > 0) and (close_p >= ma5 * 0.995))
            or ((ma20 > 0) and (close_p >= ma20 * 0.985))
        )

        candle_ok = bool((close_p >= open_p * 0.992) or (close_p >= prev_close))
        wick_ok = bool(wick_pct <= 65.0)
        obv_ok = bool((obv_slope >= -3.0) or (prev_obv <= 0) or (obv >= prev_obv * 0.995))

        wc = white_cloud_bundle or {}
        wc_state = str(wc.get("state", "") or "").strip()
        wc_near_n = int(wc.get("near_n", 0) or 0)
        cloud_ok = bool(
            (wc_state == "below" and wc_near_n >= 1)
            or (wc_state == "inside")
            or (wc_state == "mixed" and int(wc.get("below_n", 0) or 0) >= 1 and int(wc.get("inside_n", 0) or 0) >= 1)
        )

        hard_fail = bool(
            (long_floor > 0 and close_p < long_floor * 0.75)
            or (vma20 > 0 and vol < vma20 * 0.45)
            or (wick_pct >= 140.0)
            or (ma20 > 0 and close_p < ma20 * 0.88)
        )

        score = sum([
            1 if vol_ok else 0,
            1 if reclaim_ok else 0,
            1 if candle_ok else 0,
            1 if wick_ok else 0,
            1 if long_ok else 0,
            1 if cloud_ok else 0,
            1 if obv_ok else 0,
        ])

        ok = bool((not hard_fail) and score >= 5 and vol_ok and long_ok)
        weak = bool((not ok) and (not hard_fail) and score >= 3)
        caution = bool(
            hard_fail
            or score <= 2
            or ((not vol_ok) and (not reclaim_ok))
            or (wc_state == "above" and score < 6)
        )

        tag = ""
        comment = ""
        if ok:
            tag = "✅정제수박"
            comment = "거래량·재안착·장기저항 위치가 양호"
        elif weak:
            tag = "🟨관찰수박"
            comment = "수박 구조는 있으나 한두 가지 확인이 필요"
        elif caution:
            tag = "⚠️가짜수박주의"
            comment = "거래량·윗꼬리·장기이평 위치 중 약한 요소 존재"

        return {
            "ok": ok,
            "weak": weak,
            "caution": caution,
            "score": int(score),
            "tag": tag,
            "comment": comment,
            "vol_ok": bool(vol_ok),
            "reclaim_ok": bool(reclaim_ok),
            "candle_ok": bool(candle_ok),
            "wick_ok": bool(wick_ok),
            "long_ok": bool(long_ok),
            "cloud_ok": bool(cloud_ok),
            "obv_ok": bool(obv_ok),
            "hard_fail": bool(hard_fail),
        }
    except Exception:
        return empty.copy()



def classify_resistance_cloud_phase_from_bundle(
    white_cloud_bundle: dict,
    wm_refine_bundle: Optional[dict] = None,
    wm_bundle: Optional[dict] = None,
) -> dict:
    """
    흰구름을 장기이평대가 아니라 '미래 저항 구름'으로 해석
    - 저항전: 구름 아래
    - 저항테스트: 구름 내부 / 경계
    - 저항돌파: 구름 위 (단, 에너지 강도에 따라 코멘트 분리)
    """
    wc = dict(white_cloud_bundle or {})
    refine = dict(wm_refine_bundle or {})
    wm = dict(wm_bundle or {})

    state = str(wc.get('state', '') or '').strip()
    near_n = int(wc.get('near_n', 0) or 0)
    late = bool(wm.get('wm_late', False))

    strong_energy = bool(
        refine.get('ok', False)
        and refine.get('vol_ok', False)
        and refine.get('candle_ok', False)
        and not late
    )

    phase = '저항혼합'
    tag = '☁ 저항혼합'
    comment = '미래 저항 구름 해석이 엇갈림'

    if state == 'below':
        phase = '저항전'
        tag = '☁ 저항전'
        if near_n >= 2:
            comment = '미래 저항 구름 아래 선취 가능 구간'
        else:
            comment = '저항 구름 아래지만 아직 거리가 있음'
    elif state == 'inside':
        phase = '저항테스트'
        tag = '☁ 저항테스트'
        comment = '미래 저항 구름을 시험하는 구간, 힘 확인 필요'
    elif state == 'above':
        phase = '저항돌파'
        tag = '☁ 저항돌파'
        if strong_energy:
            comment = '미래 저항 구름 상향 돌파, 강한 진행형'
        else:
            comment = '저항 구름 위 진행형, 추격보다 눌림 대응'
    elif state == 'mixed':
        phase = '저항혼합'
        tag = '☁ 저항혼합'
        comment = '저항 위치 판단이 혼합, 보조 참고'

    return {
        'phase': phase,
        'tag': tag,
        'comment': comment,
        'strong_energy': bool(strong_energy),
    }


def _is_breakout_priority_type(row) -> bool:
    """
    특정 종목명 대신 '돌파우선형'으로 해석하는 케이스
    - 미래 저항 구름을 이미 상향 돌파했거나
    - 강한 에너지를 동반한 테스트/돌파 진행형이며
    - 수박 초기 선취보다 진행형 성격이 더 강한 경우
    """
    def _b(x):
        try:
            return bool(x)
        except Exception:
            return False

    def _f(x, default=0.0):
        try:
            return float(x)
        except Exception:
            return default

    wc_state = str(row.get('저항구름상태', '') or '').strip()
    # 주의: 여기서 _resolve_track_display_state()를 다시 부르면
    # _resolve_track_display_state -> _is_breakout_priority_type -> _resolve_track_display_state
    # 순환 참조가 생길 수 있으므로, 원본 상태 컬럼만 직접 읽는다.
    wm_state = str(
        row.get('수박최종상태', row.get('최종상태', row.get('상태', ''))) or ''
    ).strip()
    if not wm_state:
        wm_state = str(row.get('돌파상태', row.get('선취상태', '')) or '').strip()
    strong_energy = _b(row.get('저항구름강에너지', False))
    late_flag = _b(row.get('수박디버그_late', False))

    ma224 = _f(row.get('MA224', row.get('ma224', 0)))
    close_p = _f(row.get('현재가', row.get('Close', row.get('close', 0))))
    disparity = _f(row.get('이격', row.get('Disparity', 0)))

    above_ma224 = bool(ma224 > 0 and close_p >= ma224 * 1.02)
    progressing_state = wm_state in ('Blue-1단기', 'Blue-2스윙', '후행수박')
    overheated = disparity >= 108

    if wc_state == '저항돌파' and (strong_energy or above_ma224 or progressing_state):
        return True

    if wc_state == '저항테스트' and strong_energy and above_ma224 and progressing_state and not late_flag:
        return True

    if strong_energy and above_ma224 and overheated:
        return True

    return False


def compute_breakout_mode_fields(df: pd.DataFrame) -> pd.DataFrame:
    """
    흰구름 돌파형 별도 랭킹
    - 단테 선취형과 분리
    - 저항돌파 + 에너지 강한 종목을 따로 분류
    """
    if df is None or df.empty:
        return df

    work = df.copy()

    def _b(x):
        try:
            return bool(x)
        except Exception:
            return False

    def _f(x, default=0.0):
        try:
            return float(x)
        except Exception:
            return default

    scores = []
    states = []
    comments = []
    reasons = []

    for _, row in work.iterrows():
        rc_state = str(row.get('저항구름상태', '') or '').strip()
        wm_state = _resolve_track_display_state(row, track='breakout')
        late = _b(row.get('수박디버그_late', False))
        breakout_priority = _is_breakout_priority_type(row)

        score = 0
        rs = []

        if rc_state == '저항돌파':
            score += 30
            rs.append('저항돌파')
        elif rc_state == '저항테스트':
            score += 12
            rs.append('저항테스트')
        elif rc_state == '저항전':
            score -= 8
            rs.append('저항전')
        else:
            score -= 6

        if _b(row.get('저항구름강에너지', False)):
            score += 20
            rs.append('강에너지')
        if breakout_priority:
            score += 14
            rs.append('돌파우선형')
        if _b(row.get('수박정제통과', False)):
            score += 12
            rs.append('정제통과')
        elif _b(row.get('수박정제관찰', False)):
            score += 5
            rs.append('정제관찰')
        elif _b(row.get('수박정제주의', False)):
            score -= 10
            rs.append('정제주의')

        if _b(row.get('수박정제_vol_ok', False)):
            score += 8
        if _b(row.get('수박정제_candle_ok', False)):
            score += 8
        if _b(row.get('수박정제_obv_ok', False)):
            score += 5
        if _b(row.get('5일재안착', False)):
            score += 8
            rs.append('재안착')
        elif _b(row.get('5일재안착예비', False)):
            score += 3

        if wm_state == 'Blue-2스윙':
            score += 10
            rs.append('Blue-2스윙')
        elif wm_state == 'Blue-1단기':
            score += 8
            rs.append('Blue-1')
        elif wm_state in ('초입수박', '눌림수박', 'Blue-2예비'):
            score += 4

        disparity = _f(row.get('이격', row.get('Disparity', 0)))
        if disparity >= 125:
            score -= 18
            rs.append('과열')
        elif disparity >= 118:
            score -= 10
            rs.append('이격과열')

        if late:
            score -= 15
            rs.append('late')

        if rc_state == '저항돌파' and (_b(row.get('저항구름강에너지', False)) or breakout_priority) and not late and score >= 45:
            b_state = '흰구름돌파형'
            b_comment = '미래 저항 구름을 강하게 돌파한 진행형 후보' if not breakout_priority else '돌파우선형: 선취 대응보다 저항구름 돌파 대응 우선'
        elif rc_state in ('저항돌파', '저항테스트') and score >= 28 and not late:
            b_state = '돌파관찰형'
            b_comment = '구름 돌파 또는 테스트 구간, 힘 확인 후 대응'
        else:
            b_state = '돌파제외형'
            b_comment = '돌파 에너지 부족 또는 과열/후행 가능성'

        scores.append(int(score))
        states.append(b_state)
        comments.append(b_comment)
        reasons.append(" | ".join(rs[:6]))

    work['돌파점수'] = scores
    work['돌파상태'] = states
    work['돌파코멘트'] = comments
    work['돌파이유'] = reasons
    return work


def _resolve_track_display_state(row: pd.Series, track: str = "preempt") -> str:
    # 이미 계산된 상태가 있으면 우선 사용한다.
    wm_state = str(
        row.get('수박최종상태', row.get('최종상태', row.get('상태', ''))) or ''
    ).strip()
    if wm_state:
        return wm_state

    rc_state = str(row.get('저항구름상태', '') or '').strip()
    breakout_priority = _is_breakout_priority_type(row)

    if track == 'preempt':
        pre_state = str(row.get('선취상태', row.get('단테상태', '')) or '').strip()
        if pre_state == '선취형':
            return '선취형'
        if pre_state == '선취관찰형':
            return '구조관찰'
        if pre_state == '선취제외형':
            return '선취제외'
        if rc_state == '저항전':
            return '저항전관찰'
        if rc_state == '저항테스트':
            return '저항테스트관찰'
        return '중립관찰'

    breakout_state = str(row.get('돌파상태', '') or '').strip()
    if breakout_state == '흰구름돌파형':
        return '돌파우선형' if breakout_priority else '구름돌파형'
    if breakout_state == '돌파관찰형':
        return '구름테스트관찰' if rc_state == '저항테스트' else '돌파관찰형'
    if rc_state == '저항돌파':
        return '돌파관찰형'
    if rc_state == '저항테스트':
        return '구름테스트관찰'
    return '중립관찰'


def _recommendation_phase(row: pd.Series) -> str:
    phase = str(row.get('추천단계', '') or '').strip()
    if phase:
        return phase

    stage_track = str(row.get('단계트랙', '') or '').strip()
    if stage_track:
        return stage_track

    wm_state = _resolve_track_display_state(row, track='breakout')
    rc_state = str(row.get('저항구름상태', '') or '').strip()
    refine_state = _stage_refine_state(row)
    late_flag = bool(row.get('수박디버그_late', False)) or wm_state == '후행수박'
    reanchor = bool(row.get('5일재안착', False)) or str(row.get('5일재안착태그', '') or '').strip() != ''
    clean_candle = _stage_is_clean_power_candle(row)
    disparity = 0.0
    try:
        disparity = float(row.get('이격', row.get('Disparity', 0)) or 0)
    except Exception:
        disparity = 0.0

    if late_flag or wm_state == '후행수박':
        return '후행형'

    if rc_state == '저항돌파':
        if clean_candle and refine_state != 'bad' and disparity < 118:
            return '초동발생형'
        return '돌파관찰형'

    if rc_state in ('저항전', '저항테스트'):
        if clean_candle and refine_state != 'bad' and (reanchor or wm_state in ('초입수박', '눌림수박', 'Blue-2예비')):
            return '돌파직전형'
        if refine_state in ('pass', 'watch') and (reanchor or wm_state in ('초입수박', '눌림수박', 'Blue-2예비')):
            return '선취형'
        if rc_state == '저항테스트':
            return '구름테스트관찰'
        return '구조관찰'

    return '중립관찰'


def _recommendation_priority_score(row: pd.Series) -> float:
    phase = _recommendation_phase(row)
    safe_score = 0.0
    n_score = 0.0
    stage_rank = 0.0
    disparity = 0.0
    try:
        safe_score = float(row.get('안전점수', 0) or 0)
        n_score = float(row.get('N점수', 0) or 0)
        stage_rank = float(row.get('단계랭크', 0) or 0)
        disparity = float(row.get('이격', row.get('Disparity', 0)) or 0)
    except Exception:
        pass

    phase_weight = {
        '선취형': 500,
        '돌파직전형': 430,
        '초동발생형': 320,
        '돌파관찰형': 240,
        '구름테스트관찰': 230,
        '구조관찰': 220,
        '중립관찰': 180,
        '후행형': 40,
    }.get(phase, 150)

    score = phase_weight + stage_rank * 35 + safe_score * 0.22 + n_score * 0.05

    if _stage_refine_state(row) == 'bad':
        score -= 80
    elif _stage_refine_state(row) == 'watch':
        score -= 15

    if bool(row.get('수박디버그_late', False)) or str(row.get('수박최종상태', '') or '').strip() == '후행수박':
        score -= 120

    if disparity >= 120:
        score -= 90
    elif disparity >= 115:
        score -= 55
    elif disparity >= 112:
        score -= 25

    if str(row.get('저항구름상태', '') or '').strip() == '저항돌파' and phase not in ('초동발생형',):
        score -= 18

    return float(score)


def _extract_grade_core(grade_text: str) -> str:
    grade_text = str(grade_text or '').strip()
    for g in ['SSS+', 'SSS', 'SS+', 'SS', 'S+', 'S', 'A', 'B', 'C']:
        if grade_text.endswith(g):
            return g
    return grade_text


def _cap_grade_label(grade_text: str, max_grade: str = 'SSS+') -> str:
    order = {'SSS+': 9, 'SSS': 8, 'SS+': 7, 'SS': 6, 'S+': 5, 'S': 4, 'A': 3, 'B': 2, 'C': 1}
    txt = str(grade_text or '').strip()
    cur = _extract_grade_core(txt)
    if cur not in order or max_grade not in order:
        return txt
    if order[cur] <= order[max_grade]:
        return txt
    prefix = txt[:len(txt) - len(cur)]
    return f"{prefix}{max_grade}"


def _recommendation_max_grade(row: pd.Series) -> str:
    phase = _recommendation_phase(row)
    disparity = 0.0
    try:
        disparity = float(row.get('이격', row.get('Disparity', 0)) or 0)
    except Exception:
        disparity = 0.0

    if phase == '후행형':
        return 'S+'
    if phase in ('구조관찰', '돌파관찰형', '구름테스트관찰'):
        return 'SS'
    if phase == '초동발생형':
        return 'SS'
    if _stage_refine_state(row) == 'bad':
        return 'S+'
    if disparity >= 118:
        return 'SS'
    return 'SSS+'


def _recommendation_summary_line(row: pd.Series) -> str:
    phase = _recommendation_phase(row)
    if phase == '선취형':
        return '선취 구간으로, 5일선 또는 구름 하단 기준 분할 접근을 검토한다.'
    if phase == '돌파직전형':
        return '돌파 직전 구간으로, 종가 강도와 윗꼬리 여부를 확인해 종가베팅 여부를 판단한다.'
    if phase == '초동발생형':
        return '초동 발생 구간으로, 추격보다 다음 눌림 지지 확인이 우선이다.'
    if phase in ('돌파관찰형', '구름테스트관찰'):
        return '중간 구간으로 진입보다는 구름 상단 안착과 재돌파 확인이 필요하다.'
    if phase == '후행형':
        return '후행 구간으로, 신규 추격보다 보유자 대응과 눌림 재확인이 중요하다.'
    return '구조는 있으나 확인 신호가 더 필요하다.'


def _recommendation_section_title(phase: str) -> str:
    phase = str(phase or '').strip()
    if phase == '선취형':
        return '📌 [오늘의 선취형 후보]'
    if phase == '돌파직전형':
        return '🚀 [오늘의 돌파직전형 추천]'
    if phase == '초동발생형':
        return '🔥 [오늘의 초동발생형 추천]'
    if phase in ('돌파관찰형', '구름테스트관찰', '구조관찰', '중립관찰'):
        return '👀 [오늘의 관찰형 참고]'
    if phase == '후행형':
        return '🛡️ [오늘의 후행형 참고]'
    return '📢 [오늘의 추천주]'


def _apply_recommendation_alignment(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or df.empty:
        return df
    out = df.copy()
    out['추천단계'] = out.apply(_recommendation_phase, axis=1)
    out['추천정렬점수'] = out.apply(_recommendation_priority_score, axis=1)
    out = out.sort_values(
        by=['추천정렬점수', '단계랭크', '안전점수', 'N점수'],
        ascending=False
    ).reset_index(drop=True)
    return out


def _build_candidate_explain_lines(row: pd.Series, track: str = "preempt") -> tuple[str, str, str]:
    def _b(x):
        try:
            return bool(x)
        except Exception:
            return False

    def _f(x, default=0.0):
        try:
            return float(x)
        except Exception:
            return default

    wm_state = _resolve_track_display_state(row, track='breakout')
    rc_state = str(row.get('저항구름상태', '') or '').strip()
    refine = '정제통과' if _b(row.get('수박정제통과', False)) else ('정제관찰' if _b(row.get('수박정제관찰', False)) else ('정제주의' if _b(row.get('수박정제주의', False)) else ''))
    has_reanchor = _b(row.get('5일재안착', False))
    has_reanchor_preview = _b(row.get('5일재안착예비', False))
    breakout_priority = _is_breakout_priority_type(row)
    late_flag = _b(row.get('수박디버그_late', False)) or (wm_state == '후행수박')
    disparity = _f(row.get('이격', row.get('Disparity', 0)))
    strong_energy = _b(row.get('저항구름강에너지', False))
    reasons = []
    lacks = []

    if track == 'preempt':
        if wm_state in ('초입수박', '눌림수박', 'Blue-2예비'):
            reasons.append(wm_state)
        elif wm_state:
            reasons.append(wm_state)

        if rc_state == '저항전':
            reasons.append('저항전')
        elif rc_state == '저항테스트':
            reasons.append('저항테스트')
        elif rc_state == '저항혼합':
            lacks.append('저항 위치 추가 확인')
        elif rc_state == '저항돌파':
            lacks.append('선취보다 눌림 확인')

        if has_reanchor:
            reasons.append('5일재안착')
        else:
            lacks.append('5일재안착 미확인')
            if has_reanchor_preview:
                lacks.append('5일재안착 예비 확인')

        if refine == '정제통과':
            reasons.append('정제통과')
        elif refine == '정제관찰':
            reasons.append('정제관찰')
            lacks.append('정제 추가 확인')
        elif refine == '정제주의':
            lacks.append('정제 보완 필요')

        if breakout_priority:
            lacks.append('돌파우선형 여부 확인')
        if late_flag:
            lacks.append('후행 구간 주의')
        if disparity >= 118:
            lacks.append('이격 과열')
        elif disparity >= 112:
            lacks.append('이격 부담')

        if rc_state == '저항전' and not late_flag:
            action = '소액 선진입보다 분할관찰이 유리하며, 5일선 재안착과 양봉 유지 시 대응합니다.' if not has_reanchor else '소액 분할 접근 가능하나, 5일선 이탈 시 보수적으로 대응합니다.'
        else:
            action = '바로 추격보다 한 번 더 확인이 유리하며, 재안착이나 거래량 보강 후 대응합니다.'
    else:
        if rc_state in ('저항돌파', '저항테스트'):
            reasons.append(rc_state)
        if strong_energy:
            reasons.append('강에너지')
        if breakout_priority:
            reasons.append('돌파우선형')
        if has_reanchor:
            reasons.append('재안착')
        elif has_reanchor_preview:
            lacks.append('재안착 예비 확인')

        if refine == '정제통과':
            reasons.append('정제통과')
        elif refine == '정제관찰':
            reasons.append('정제관찰')
            lacks.append('정제 추가 확인')
        elif refine == '정제주의':
            lacks.append('정제 보완 필요')

        if wm_state in ('초입수박', '눌림수박', 'Blue-2예비'):
            reasons.append(wm_state)
        elif wm_state == '후행수박':
            lacks.append('후행 구간 주의')

        if rc_state == '저항테스트':
            lacks.append('구름 상단 안착 확인')
        if not strong_energy and rc_state == '저항돌파':
            lacks.append('거래량/힘 유지 확인')
        if disparity >= 118:
            lacks.append('이격 과열')
        elif disparity >= 112:
            lacks.append('추격 부담')
        if late_flag:
            lacks.append('후행 구간 주의')

        if rc_state == '저항돌파':
            action = '돌파 추격보다 구름 상단 또는 5일선 눌림 확인 후 대응하는 편이 유리합니다.'
        else:
            action = '돌파 테스트 구간으로, 거래량 유지와 구름 상단 안착을 확인한 뒤 대응합니다.'

    def _uniq(items):
        out = []
        seen = set()
        for x in items:
            if x and x not in seen:
                seen.add(x)
                out.append(x)
        return out

    reasons = _uniq(reasons)
    lacks = _uniq(lacks)
    selected = ' + '.join(reasons[:4]) if reasons else '핵심 근거 집계 중'
    lacking = ' / '.join(lacks[:3]) if lacks else ('구조는 양호하나 추격 여부는 별도 확인' if track == 'breakout' else '큰 부족은 없지만 위치 확인 후 대응')
    return selected, lacking, action


def _stage_wick_pct(row: pd.Series) -> float:
    for key in ['윗꼬리비율', '상꼬리비율', 'wick_pct']:
        try:
            v = row.get(key, None)
            if v is not None and str(v) != '' and not pd.isna(v):
                return float(v)
        except Exception:
            pass
    try:
        return float(_calc_upper_wick_ratio(row) * 100.0)
    except Exception:
        return 999.0


def _stage_body_pct(row: pd.Series) -> float:
    for key in ['몸통비율', 'body_pct', 'Body_Pct']:
        try:
            v = row.get(key, None)
            if v is not None and str(v) != '' and not pd.isna(v):
                return float(v)
        except Exception:
            pass
    try:
        return float(_calc_body_ratio(row) * 100.0)
    except Exception:
        return 0.0


def _stage_close_high_ratio(row: pd.Series) -> float:
    try:
        high_p = float(row.get('High', 0) or 0)
        close_p = float(row.get('Close', row.get('현재가', 0)) or 0)
        if high_p <= 0:
            return 0.0
        return close_p / high_p
    except Exception:
        return 0.0


def _stage_is_clean_power_candle(row: pd.Series) -> bool:
    try:
        open_p = float(row.get('Open', 0) or 0)
        close_p = float(row.get('Close', row.get('현재가', 0)) or 0)
    except Exception:
        return False
    if close_p <= open_p or open_p <= 0:
        return False
    wick_pct = _stage_wick_pct(row)
    body_pct = _stage_body_pct(row)
    close_high = _stage_close_high_ratio(row)
    return body_pct >= 2.0 and wick_pct <= 30.0 and close_high >= 0.965


def _stage_refine_state(row: pd.Series) -> str:
    if bool(row.get('수박정제통과', False)):
        return 'pass'
    if bool(row.get('수박정제관찰', False)):
        return 'watch'
    if bool(row.get('수박정제주의', False)):
        return 'bad'
    tag = str(row.get('수박정제태그', '') or '').strip()
    if '✅' in tag or '정제수박' in tag:
        return 'pass'
    if '관찰수박' in tag:
        return 'watch'
    if '가짜수박주의' in tag:
        return 'bad'
    return 'none'


def _build_stage_track_frames(pass_df: pd.DataFrame):
    empty = pd.DataFrame()
    if pass_df is None or pass_df.empty:
        return empty, empty, empty

    work = pass_df.copy()
    for col in ['단계트랙', '단계트랙점수', '단계트랙코멘트']:
        if col not in work.columns:
            work[col] = '' if col != '단계트랙점수' else 0

    tracks = []
    scores = []
    comments = []

    for _, row in work.iterrows():
        rc_state = str(row.get('저항구름상태', '') or '').strip()
        wm_state = _resolve_track_display_state(row, track='breakout')
        refine_state = _stage_refine_state(row)
        late_flag = bool(row.get('수박디버그_late', False)) or wm_state == '후행수박'
        reanchor = bool(row.get('5일재안착', False)) or str(row.get('5일재안착태그', '') or '').strip() != ''
        clean_candle = _stage_is_clean_power_candle(row)
        wick_pct = _stage_wick_pct(row)
        body_pct = _stage_body_pct(row)
        close_high = _stage_close_high_ratio(row)
        stage_status = str(row.get('단계상태', '') or '').strip()
        n_score = float(row.get('N점수', 0) or 0)
        safe_score = float(row.get('안전점수', 0) or 0)

        score = safe_score + (n_score * 0.15)
        if clean_candle:
            score += 80
        if reanchor:
            score += 25
        if refine_state == 'pass':
            score += 35
        elif refine_state == 'watch':
            score += 12
        elif refine_state == 'bad':
            score -= 70
        if late_flag:
            score -= 80
        if wick_pct > 35:
            score -= 40
        if body_pct >= 5.0:
            score += 10
        if stage_status == 'PASS_A':
            score += 20

        track = ''
        comment = ''

        if rc_state == '저항돌파' and clean_candle and not late_flag and refine_state != 'bad':
            track = '초동발생형'
            comment = '이미 강한 양봉과 함께 돌파가 발생한 진행형으로, 추격보다 눌림 대응이 유리'
            score += 40
        elif rc_state in ('저항전', '저항테스트') and clean_candle and not late_flag and refine_state != 'bad':
            if reanchor or wm_state in ('초입수박', '눌림수박', 'Blue-2예비'):
                track = '돌파직전형'
                comment = '장대양봉이 깔끔하고 윗꼬리가 짧은 편이라 종가베팅/돌파직전 대응 후보'
                score += 35
        elif rc_state in ('저항전', '저항테스트') and not late_flag and refine_state in ('pass', 'watch'):
            if wm_state in ('초입수박', '눌림수박', 'Blue-2예비') or reanchor:
                track = '선취형'
                comment = '저항 아래 또는 테스트 구간에서 구조를 먼저 보는 초기 선취 후보'
                score += 20

        # 돌파 직전형/선취형은 윗꼬리 긴 종목 제거
        if track in ('선취형', '돌파직전형') and not clean_candle:
            track = ''
            comment = ''
        if track == '돌파직전형' and (wick_pct > 28 or close_high < 0.965):
            track = ''
            comment = ''
        if track == '초동발생형' and (wick_pct > 35 or close_high < 0.955):
            track = ''
            comment = ''

        tracks.append(track)
        scores.append(int(score))
        comments.append(comment)

    work['단계트랙'] = tracks
    work['단계트랙점수'] = scores
    work['단계트랙코멘트'] = comments

    def _top(df_in: pd.DataFrame) -> pd.DataFrame:
        if df_in is None or df_in.empty:
            return pd.DataFrame()
        return df_in.sort_values(by=['단계트랙점수', '안전점수', 'N점수'], ascending=False).head(5).reset_index(drop=True)

    preempt_df = _top(work[work['단계트랙'] == '선취형'].copy())
    ready_df = _top(work[work['단계트랙'] == '돌파직전형'].copy())
    burst_df = _top(work[work['단계트랙'] == '초동발생형'].copy())
    return preempt_df, ready_df, burst_df


def _text_block_header(icon: str, title: str) -> str:
    return f"{icon} [{title}]\n\n"


def _text_block_footer() -> str:
    return "\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n"


def _wrap_stock_card(card_text: str, rank: int = 1) -> str:
    body = str(card_text or '').strip()
    if not body:
        return ''
    divider = '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━'
    prefix = '' if rank == 1 else '\n'
    return f"{prefix}{divider}\n{body}\n{divider}\n\n"


def _strict_fake_filter_enabled() -> bool:
    return str(os.getenv('STRICT_FAKE_FILTER', '0')).strip().lower() in ('1', 'true', 'y', 'yes', 'on')


def _is_fake_caution_row(row) -> bool:
    try:
        if bool(row.get('수박정제주의', False)):
            return True
    except Exception:
        pass
    tag = str(row.get('수박정제태그', '') or '').strip()
    comment = str(row.get('수박정제코멘트', '') or '').strip()
    return ('가짜수박주의' in tag) or ('가짜수박' in comment)


def _filter_fake_rows_for_actionable_block(df: pd.DataFrame, title: str) -> pd.DataFrame:
    if df is None or df.empty or not _strict_fake_filter_enabled():
        return df
    title = str(title or '')
    filter_keywords = ('선취 후보', '선취 관찰', '흰구름 돌파 후보', '흰구름 돌파 관찰', '초입수박', '눌림수박', '파란점선', 'Blue-2')
    if not any(k in title for k in filter_keywords):
        return df
    try:
        filtered = df[~df.apply(_is_fake_caution_row, axis=1)].copy()
        return filtered
    except Exception:
        return df


def build_refine_validation_text(row) -> str:
    try:
        issues = []
        passed = []

        def add_issue(ok_key: str, label: str):
            val = row.get(ok_key, True)
            try:
                ok = bool(val)
            except Exception:
                ok = True
            if ok:
                passed.append(label)
            else:
                issues.append(label)

        add_issue('수박정제_vol_ok', '거래량')
        add_issue('수박정제_reclaim_ok', '5일재안착')
        add_issue('수박정제_candle_ok', '양봉/캔들')
        add_issue('수박정제_wick_ok', '윗꼬리')
        add_issue('수박정제_long_ok', '장기이평/중기저항')
        add_issue('수박정제_cloud_ok', '저항구름 안착')
        add_issue('수박정제_obv_ok', 'OBV매집')

        disparity = _rc_float(row, '이격', _rc_float(row, 'Disparity', 0))
        if disparity >= 118:
            issues.append(f'이격과열({int(disparity)})')

        fake = _is_fake_caution_row(row)
        observe = False
        try:
            observe = bool(row.get('수박정제관찰', False))
        except Exception:
            observe = False
        good = False
        try:
            good = bool(row.get('수박정제통과', False))
        except Exception:
            good = False

        if fake:
            return '의심사유: ' + ' / '.join(issues[:5]) if issues else '의심사유: 패턴 품질 저하'
        if observe and issues:
            return '보완필요: ' + ' / '.join(issues[:4])
        if good:
            keep = passed[:4]
            return '통과항목: ' + ' / '.join(keep) if keep else '통과항목: 기본 검증 통과'
        return ''
    except Exception:
        return ''


def build_stage_track_block(title: str, df: pd.DataFrame) -> str:
    if df is None or df.empty:
        return ''

    lines = [_text_block_header("🚀", title)]
    for rank, (_, item) in enumerate(df.head(5).iterrows(), 1):
        item2 = enrich_row_with_human_commentary(item)
        comment = str(item2.get('단계트랙코멘트', '') or '').strip()
        card = (
            f"{rank}) [{item2.get('종목명', '')}]\n"
            f"- 단계: {describe_stage_status(str(item2.get('단계상태', 'N/A')))} | {item2.get('단계태그', '')}\n"
            f"- S1:{item2.get('S1날짜', '-')}, S2:{item2.get('S2날짜', '-')}, S3:{item2.get('S3날짜', '-')}\n"
            f"- N조합: {item2.get('N조합', '')}" + (f" | {item2.get('time_sym_tag', '')}" if str(item2.get('time_sym_tag', '')).strip() else '') + "\n"
            + (f"- 재안착: {item2.get('5일재안착태그', '')} | {item2.get('5일재안착코멘트', '')}\n" if str(item2.get('5일재안착태그', '')).strip() else '')
            + (f"- 저항구름: {item2.get('저항구름태그', '')} | {item2.get('저항구름코멘트', '')}\n" if str(item2.get('저항구름태그', '')).strip() else '')
            + (f"- 정제: {item2.get('수박정제태그', '')} | {item2.get('수박정제코멘트', '')}\n" if str(item2.get('수박정제태그', '')).strip() else '')
            + (f"- 해석: {comment}\n" if comment else '')
            + f"- 재무: {item2.get('재무', '미계산')} | 수급: {item2.get('수급', '미계산')}\n"
            + (f"- 수급요약: {item2.get('수급요약', '')}\n" if str(item2.get('수급요약', '')).strip() else '')
            + (f"- 오늘수급: {item2.get('수급당일', '')}\n" if str(item2.get('수급당일', '')).strip() else '')
            + (f"- 외인보유: {item2.get('외인보유요약', '')}\n" if str(item2.get('외인보유요약', '')).strip() and str(item2.get('외인보유요약', '')).strip() != '미확인' else '')
            + f"- 안전:{item2.get('안전점수', 0)} | N점수:{item2.get('N점수', 0)} | 단계점수:{item2.get('단계트랙점수', 0)}"
        )
        lines.append(_wrap_stock_card(append_interpretation_to_block(card, item2), rank=rank))
    return ''.join(lines).rstrip() + "\n"


def build_breakout_state_block(title: str, df: pd.DataFrame) -> str:
    df = _filter_fake_rows_for_actionable_block(df, title)
    if df is None or df.empty:
        return f"🚀 [{title}]\n- 해당 종목 없음\n"

    lines = [_text_block_header("🚀", title)]
    for rank, (_, row) in enumerate(df.head(5).iterrows(), start=1):
        item2 = enrich_row_with_human_commentary(row)
        name = str(item2.get('종목명', item2.get('name', '')) or '').strip()
        code = str(item2.get('code', item2.get('종목코드', '')) or '').strip()
        wm_state = _resolve_track_display_state(item2, track='breakout')
        score = int(float(item2.get('돌파점수', 0) or 0))
        comment = str(item2.get('돌파코멘트', '') or '').strip()
        reason = str(item2.get('돌파이유', '') or '').strip()
        rc_tag = str(item2.get('저항구름태그', '') or '').strip()
        refine_tag = str(item2.get('수박정제태그', '') or '').strip()
        refine_check = build_refine_validation_text(item2)
        selected, lacking, action = _build_candidate_explain_lines(item2, track='breakout')

        card = (
            f"{rank}) {name}({code})\n"
            f"- 상태: {wm_state} | 돌파점수:{score}\n"
            + (f"- 저항구름: {rc_tag}\n" if rc_tag else "")
            + (f"- 정제: {refine_tag}\n" if refine_tag else "")
            + (f"- 해석: {comment}\n" if comment else "")
            + (f"- 이유: {reason}\n" if reason else "")
            + (f"- 선정 이유: {selected}\n" if selected else "")
            + (f"- 부족한 점: {lacking}\n" if lacking else "")
            + (f"- 추천 대응: {action}\n" if action else "")
        )
        lines.append(_wrap_stock_card(append_interpretation_to_block(card, item2), rank=rank))
    return ''.join(lines).rstrip() + "\n"


def compute_dante_mode_fields(df: pd.DataFrame) -> pd.DataFrame:
    """
    선취 모드 전용 후처리:
    - 일반 모드는 유지
    - 선취형은 장기이평/저항구름/수박상태를 우선시한 별도 랭킹
    """
    if df is None or df.empty:
        return df

    work = df.copy()

    def _b(x):
        try:
            return bool(x)
        except Exception:
            return False

    def _i(x, default=0):
        try:
            return int(float(x))
        except Exception:
            return default

    def _f(x, default=0.0):
        try:
            return float(x)
        except Exception:
            return default

    dante_scores = []
    dante_states = []
    dante_comments = []
    dante_reasons = []
    alias_states = []
    dante_tracks = []

    for _, row in work.iterrows():
        wc_state = str(row.get('저항구름상태', '') or '').strip()
        wm_state = _resolve_track_display_state(row, track='breakout')

        ma112 = _f(row.get('MA112', row.get('ma112', 0)))
        ma224 = _f(row.get('MA224', row.get('ma224', 0)))
        ma448 = _f(row.get('MA448', row.get('ma448', 0)))
        close_p = _f(row.get('현재가', row.get('Close', row.get('close', 0))))
        breakout_priority = _is_breakout_priority_type(row)

        d_score = 0
        reasons = []

        long_bear_stack = bool(ma112 > 0 and ma224 > 0 and ma448 > 0 and ma112 < ma224 < ma448)
        below_long_major = bool(ma224 > 0 and close_p <= ma224 * 1.05)
        below_long_soft = bool(ma224 > 0 and close_p <= ma224 * 1.10)

        if long_bear_stack:
            d_score += 20
            reasons.append("장기역배열")
        elif below_long_major:
            d_score += 14
            reasons.append("장기저항아래")
        elif below_long_soft:
            d_score += 6
            reasons.append("장기저항근처")
        else:
            d_score -= 18
            reasons.append("장기저항근접")

        if wc_state == '저항전':
            if _i(row.get('흰구름근접투표', 0)) >= 2:
                d_score += 25
                reasons.append("저항전근접")
            else:
                d_score += 18
                reasons.append("저항전")
        elif wc_state == '저항테스트':
            d_score += 10
            reasons.append("저항테스트")
        elif wc_state == '저항혼합':
            d_score += 4
            reasons.append("저항혼합")
        elif wc_state == '저항돌파':
            d_score -= 28
            reasons.append("저항돌파")

        if wm_state == '눌림수박':
            d_score += 22
            reasons.append("눌림수박")
        elif wm_state == '초입수박':
            d_score += 18
            reasons.append("초입수박")
        elif wm_state == 'Blue-2예비':
            d_score += 16
            reasons.append("Blue-2예비")
        elif wm_state == 'Blue-2스윙':
            d_score += 8
            reasons.append("Blue-2스윙")
        elif wm_state == 'Blue-1단기':
            d_score -= 10
            reasons.append("Blue-1진행")
        elif wm_state == '후행수박':
            d_score -= 30
            reasons.append("후행수박")

        if _b(row.get('5일재안착', False)):
            d_score += 15
            reasons.append("5일재안착")
        elif _b(row.get('5일재안착예비', False)):
            d_score += 7
            reasons.append("5일재안착예비")

        if _b(row.get('수박정제통과', False)):
            d_score += 12
            reasons.append("정제통과")
        elif _b(row.get('수박정제관찰', False)):
            d_score += 4
            reasons.append("정제관찰")
        elif _b(row.get('수박정제주의', False)):
            d_score -= 12
            reasons.append("정제주의")

        tag_text = " ".join([
            str(row.get('N조합', '') or ''),
            str(row.get('태그', '') or ''),
            str(row.get('수박태그', '') or ''),
        ])
        if ('독사' in tag_text) or ('독사수급전환' in tag_text):
            d_score += 8
            reasons.append("독사계열")
        if '돌반지' in tag_text:
            d_score += 8
            reasons.append("돌반지계열")
        if ('BB40' in tag_text) or ('BB30' in tag_text):
            d_score += 8
            reasons.append("BB응축")
        if ('⏱9근접' in tag_text) or ('⏱9예비' in tag_text):
            d_score += 5
            reasons.append("시간창")
        if ('삼각' in tag_text) or ('triangle' in tag_text.lower()):
            d_score += 6
            reasons.append("삼각수렴")

        if _b(row.get('수박정제_vol_ok', False)):
            d_score += 6
        if _b(row.get('수박정제_obv_ok', False)):
            d_score += 4
        if _b(row.get('수박정제_wick_ok', False)):
            d_score += 3
        if _b(row.get('수박정제_candle_ok', False)):
            d_score += 4

        late_flag = _b(row.get('수박디버그_late', False))
        if late_flag:
            d_score -= 24
            reasons.append("late")

        if breakout_priority:
            d_score -= 24
            reasons.append("돌파우선형")

        disparity = _f(row.get('이격', row.get('Disparity', 0)))
        if disparity >= 118:
            d_score -= 10
            reasons.append("이격과열")
        elif disparity >= 112:
            d_score -= 4

        lb_bonus = _detect_long_bottom_preempt_bonus(row)
        d_score += safe_int(lb_bonus.get('bonus', 0), 0)
        if lb_bonus.get('track'):
            reasons.append(lb_bonus.get('track'))

        if (
            d_score >= 55
            and wc_state in ('저항전', '저항테스트', '저항혼합')
            and wm_state in ('눌림수박', '초입수박', 'Blue-2예비')
            and not late_flag
            and not breakout_priority
        ):
            legacy_state = '단테선취형'
            alias_state = '선취형'
            d_comment = '장기저항 아래/근처에서 초기 선취에 가까운 구조'
        elif (
            d_score >= 40
            and wc_state in ('저항전', '저항테스트', '저항혼합')
            and wm_state in ('눌림수박', '초입수박', 'Blue-2예비', 'Blue-2스윙')
            and not late_flag
            and not breakout_priority
        ):
            legacy_state = '단테관찰형'
            alias_state = '선취관찰형'
            d_comment = '좋은 구조지만 한두 가지 확인 후 접근이 유리'
        else:
            legacy_state = '단테제외형'
            alias_state = '선취제외형'
            d_comment = '선취 대응보다 진행/후행/과열 또는 구조 미흡 가능성' if not breakout_priority else '돌파우선형: 선취 대응보다 저항구름 돌파 대응 우선'

        dante_scores.append(int(d_score))
        dante_states.append(legacy_state)
        alias_states.append(alias_state)
        dante_comments.append(d_comment)
        dante_reasons.append(" | ".join(reasons[:6]))
        dante_tracks.append(lb_bonus.get('track', '박스응축형' if alias_state in ('선취형', '선취관찰형') else ''))

    work['단테점수'] = dante_scores
    work['단테상태'] = dante_states
    work['단테코멘트'] = dante_comments
    work['단테이유'] = dante_reasons
    work['선취점수'] = dante_scores
    work['선취상태'] = alias_states
    work['선취코멘트'] = dante_comments
    work['선취이유'] = dante_reasons
    work['선취트랙'] = dante_tracks
    return work


def build_dante_state_block(title: str, df: pd.DataFrame) -> str:
    if df is None or df.empty:
        return f"🧭 [{title}]\n- 해당 종목 없음\n"

    lines = [f"🧭 [{title}]\n\n"]

    for rank, (_, row) in enumerate(df.head(5).iterrows(), start=1):
        item2 = enrich_row_with_human_commentary(row)
        name = str(item2.get('종목명', item2.get('name', '')) or '').strip()
        code = str(item2.get('code', item2.get('종목코드', '')) or '').strip()
        state = _resolve_track_display_state(item2, track='preempt')
        d_score = int(float(item2.get('선취점수', item2.get('단테점수', 0)) or 0))
        comment = str(item2.get('선취코멘트', item2.get('단테코멘트', '')) or '').strip()
        reason = str(item2.get('선취이유', item2.get('단테이유', '')) or '').strip()
        cloud_tag = str(item2.get('저항구름태그', '') or '').strip()
        refine_tag = str(item2.get('수박정제태그', '') or '').strip()
        refine_check = build_refine_validation_text(item2)
        ma5_tag = str(item2.get('5일재안착태그', '') or '').strip()
        rn_tag = str(item2.get('라운드넘버태그', '') or '').strip()
        rn_comment = str(item2.get('라운드넘버코멘트', '') or '').strip()
        preempt_track = str(item2.get('선취트랙', '') or '').strip()
        selected, lacking, action = _build_candidate_explain_lines(item2, track='preempt')

        block = (
            f"{rank}) {name}({code})\n"
            f"- 상태: {state} | 선취점수:{d_score}\n"
            + (f"- 선취트랙: {preempt_track}\n" if preempt_track else "")
            + (f"- 저항구름: {cloud_tag}\n" if cloud_tag else "")
            + (f"- 재안착: {ma5_tag}\n" if ma5_tag else "")
            + (f"- 라운드가격: {rn_tag} | {rn_comment}\n" if rn_tag else "")
            + (f"- 정제: {refine_tag}\n" if refine_tag else "")
            + (f"- 정제검증: {refine_check}\n" if refine_check else "")
            + (f"- 해석: {comment}\n" if comment else "")
            + (f"- 이유: {reason}\n" if reason else "")
            + (f"- 선정 이유: {selected}\n" if selected else "")
            + (f"- 부족한 점: {lacking}\n" if lacking else "")
            + (f"- 추천 대응: {action}\n" if action else "")
        )

        lines.append(_wrap_stock_card(append_interpretation_to_block(block, item2).rstrip(), rank=rank))

    return ''.join(lines).rstrip() + '\n'

def build_watermelon_guide_block() -> str:
    lines = [
        "🍉 [수박 상태 가이드]",
        "- 초입수박: 구조가 막 살아나는 초동 회복형 | 대응: 소액 탐색, 거래량·5일재안착 확인",
        "- 눌림수박: 가장 실전적인 눌림 재진입형 | 대응: 주력 관찰, 재안착/양봉 우대",
        "- 빨강수박: 재점화 직전 경계 구간 | 대응: 확인매수 대기",
        "- 파란점선: 실행 타점 | 대응: 분할 진입, 손절 명확화",
        "- 후행수박: 한 박자 늦은 자리 | 대응: 원칙적 관망",
        "- 참고: 초록은 독립 상태가 아니라 초입/눌림 관찰군 요약입니다",
        "- 저항구름: 미래 저항 구름의 저항전/저항테스트/저항돌파 해석 참고",
        "- 정제수박: 좋은 수박/관찰수박/가짜수박주의를 구분하는 보조 필터",
    ]
    return "\n".join(lines) + "\n"


def build_watermelon_summary_block(df: pd.DataFrame) -> str:
    if df is None or df.empty:
        return "🍉 [수박 상태 요약]\n- 집계 대상 없음\n"
    work = df.copy()
    if "수박최종상태" not in work.columns:
        work["수박최종상태"] = work.get("수박상태명", "")
    counts = work["수박최종상태"].fillna("").astype(str).value_counts().to_dict()
    intro_n = int(counts.get("초입수박", 0))
    pull_n = int(counts.get("눌림수박", 0))
    blue1_n = int(counts.get("Blue-1단기", 0))
    blue2_n = int(counts.get("Blue-2스윙", 0))
    blue2_preview_n = int(counts.get("Blue-2예비", 0))
    late_n = int(counts.get("후행수박", 0))
    green_n = intro_n + pull_n
    red_n = blue1_n + blue2_n + blue2_preview_n

    lines = [
        "🍉 [수박 상태 요약]",
        f"- 관찰군(초록): {green_n}개 = 초입 {intro_n} / 눌림 {pull_n}",
        f"- 재점화군(빨강): {red_n}개 = Blue-1 {blue1_n} / Blue-2 {blue2_n} / 예비 {blue2_preview_n}",
        f"- 후행수박: {late_n}개",
    ]
    if red_n == 0 and green_n > 0:
        lines.append("- 해석: 관찰군은 있으나 재점화 확정은 아직 적음")
    elif red_n > 0:
        lines.append("- 해석: 재점화/실행 타점 후보가 실제로 발생 중")
    return "\n".join(lines) + "\n"

def build_watermelon_state_block(title: str, df: pd.DataFrame) -> str:
    if df is None or df.empty:
        return f"🍉 [{title}]\n- 해당 종목 없음\n"

    lines = [f"🍉 [{title}]\n\n"]

    for rank, (_, row) in enumerate(df.head(5).iterrows(), 1):
        item = enrich_row_with_human_commentary(row)
        name = str(item.get('종목명', item.get('name', '')) or '').strip()
        code = str(item.get('code', item.get('종목코드', '')) or '').strip()
        state = str(item.get('수박최종상태', item.get('수박상태명', '')) or '').strip()
        grade = str(item.get('수박상태등급', item.get('wm_state_grade', '')) or '').strip()
        cloud_tag = str(item.get('저항구름태그', '') or '').strip()
        refine_tag = str(item.get('수박정제태그', '') or '').strip()
        refine_check = build_refine_validation_text(item)
        easy = str(item.get('easy_interpretation', '') or '').strip()
        need_check = str(item.get('need_check', '') or '').strip()
        action = str(item.get('action_summary', '') or '').strip()
        caution = str(item.get('caution', '') or '').strip()
        final_label = str(item.get('final_label', '') or '').strip()
        score_summary = str(item.get('score_summary', '') or '').strip()

        card = (
            f"{rank}) {name}({code})\n"
            f"- 상태: {state} | 등급:{grade}\n"
            + (f"- 저항구름: {cloud_tag}\n" if cloud_tag else "")
            + (f"- 정제: {refine_tag}\n" if refine_tag else "")
            + (f"- 정제검증: {refine_check}\n" if refine_check else "")
            + _render_kki_lines(item)
            + (f"- 쉬운 해설: {easy}\n" if easy else "")
            + (f"- 확인 필요: {need_check}\n" if need_check else "")
            + (f"- 대응 요약: {action}\n" if action else "")
            + (f"- 최종 판정: {final_label}\n" if final_label else "")
            + (f"- 주의 포인트: {caution}\n" if caution else "")
            + (f"- 점수 해석: {score_summary}\n" if score_summary else "")
        )

        lines.append(_wrap_stock_card(card.rstrip(), rank=rank))

    return ''.join(lines).rstrip() + '\n'

def build_watermelon_debug_block(title: str, df: pd.DataFrame) -> str:
    """
    수박/파란점 상태 분류가 왜 통과/실패했는지 디버그용으로 보여준다.
    누락 컬럼이 있어도 죽지 않도록 안전하게 0/빈값으로 처리한다.
    """
    if df is None or df.empty:
        return f"🔬 [{title}]\n- 해당 종목 없음\n"

    def _b(row, col: str, default: int = 0) -> int:
        try:
            v = row.get(col, default)
            if pd.isna(v):
                return default
            if isinstance(v, (bool, np.bool_)):
                return int(bool(v))
            return int(v)
        except Exception:
            try:
                return int(bool(row.get(col, default)))
            except Exception:
                return default

    lines = [f"🔬 [{title}]\n"]
    for rank, (_, row) in enumerate(df.iterrows(), 1):
        name = str(row.get('종목명', ''))
        code = str(row.get('code', ''))
        state = str(row.get('수박최종상태', row.get('수박상태명', '')))

        gate_parts = [
            f"intro_box={_b(row, '수박디버그_intro_box')}",
            f"change={_b(row, '수박디버그_change')}",
            f"red_raw={_b(row, '수박디버그_red_raw')}",
            f"red_onset={_b(row, '수박디버그_red_onset')}",
            f"blue1_onset={_b(row, '수박디버그_blue1_onset')}",
            f"pullback_box={_b(row, '수박디버그_pullback_box')}",
            f"red2_raw={_b(row, '수박디버그_red2_raw')}",
            f"blue2_onset={_b(row, '수박디버그_blue2_onset')}",
            f"late={_b(row, '수박디버그_late')}",
            f"blue_confirm={_b(row, 'blue_confirm', -1)}",
        ]

        intro_sub_parts = [
            f"range={_b(row, '수박디버그_box_range_ok')}",
            f"attack_band={_b(row, '수박디버그_attack_band_ok')}",
            f"ret7={_b(row, '수박디버그_ret7_ok')}",
            f"ret15={_b(row, '수박디버그_ret15_ok')}",
            f"ret20={_b(row, '수박디버그_ret20_ok')}",
            f"dayup={_b(row, '수박디버그_dayup_ok')}",
            f"top_near={_b(row, '수박디버그_top_near_ok')}",
            f"vol_calm={_b(row, '수박디버그_vol_calm_ok')}",
            f"no_blue1={_b(row, '수박디버그_no_blue1_ok')}",
            f"no_blue2={_b(row, '수박디버그_no_blue2_ok')}",
            f"not_late={_b(row, '수박디버그_not_late_ok')}",
        ]

        red2_sub_parts = [
            f"pb={_b(row, '수박디버그_red2_pullback_ok')}",
            f"chg={_b(row, '수박디버그_red2_change_ok')}",
            f"c20={_b(row, '수박디버그_red2_close_ma20_ok')}",
            f"m520={_b(row, '수박디버그_red2_ma5_ma20_ok')}",
            f"pbox={_b(row, '수박디버그_red2_prevbox_ok')}",
            f"vol={_b(row, '수박디버그_red2_vol_ok')}",
            f"candle={_b(row, '수박디버그_red2_candle_ok')}",
            f"not_late={_b(row, '수박디버그_red2_not_late_ok')}",
            f"struct={_b(row, '수박디버그_red2_structure_ok')}",
            f"soft={_b(row, '수박디버그_red2_soft_ok')}",
            f"strong={_b(row, '수박디버그_blue2_strong')}",
            f"preview={_b(row, '수박디버그_blue2_preview')}",
            f"prev_clear={_b(row, '수박디버그_blue2_prev_clear_ok')}",
            f"ctx={_b(row, '수박디버그_blue2_context_ok')}",
            f"vol2={_b(row, '수박디버그_blue2_vol2_ok')}",
        ]

        lines.append(
            f"{rank}) {name}({code})\n"
            f"- 최종상태: {state}\n"
            f"- gate: {' / '.join(gate_parts)}\n"
            f"- intro_sub: {' / '.join(intro_sub_parts)}\n"
            f"- red2_sub: {' / '.join(red2_sub_parts)}\n"
        )

    return "\n".join(lines)

