def _normalize_test_profile(raw: str) -> str:
    profile = str(raw or '').strip().upper()
    alias = {
        'REAL': 'REAL_FULL',
        'REAL_FULL': 'REAL_FULL',
        'LIVE': 'REAL_FULL',
        'PROD': 'REAL_FULL',
        'PRODUCTION': 'REAL_FULL',
        'TEST': 'TEST_FULL',
        'TEST_FULL': 'TEST_FULL',
        'FULL': 'TEST_FULL',
        'TEST_FAST': 'TEST_FAST',
        'FAST': 'TEST_FAST',
        'QUICK': 'TEST_FAST',
    }
    return alias.get(profile, '')


