_weather_cache = {}

def _clean_unique_index(df: pd.DataFrame) -> pd.DataFrame:
    df = df.copy()
    df.index = pd.to_datetime(df.index)
    df = df.sort_index()
    df = df[~df.index.duplicated(keep='last')]
    return df

def prepare_historical_weather():
    cache_key = datetime.now().strftime('%Y-%m-%d')
    if cache_key in _weather_cache:
        log_debug("✅ 날씨 데이터 캐시 사용")
        return _weather_cache[cache_key]

    start_point = (datetime.now() - timedelta(days=600)).strftime('%Y-%m-%d')

    ndx = fdr.DataReader('^IXIC', start=start_point)[['Close']]
    sp5 = fdr.DataReader('^GSPC', start=start_point)[['Close']]
    vix = fdr.DataReader('^VIX', start=start_point)[['Close']]

    # ✅ 인덱스 정리
    ndx = _clean_unique_index(ndx)
    sp5 = _clean_unique_index(sp5)
    vix = _clean_unique_index(vix)

    # ✅ 컬럼명 먼저 변경
    ndx = ndx.rename(columns={'Close': 'ixic_close'})
    sp5 = sp5.rename(columns={'Close': 'sp500_close'})
    vix = vix.rename(columns={'Close': 'vix_close'})

    # ✅ 이동평균 계산
    ndx['ixic_ma5'] = ndx['ixic_close'].rolling(5).mean()
    sp5['sp500_ma5'] = sp5['sp500_close'].rolling(5).mean()
    vix['vix_ma5'] = vix['vix_close'].rolling(5).mean()

    # ✅ concat
    weather_df = pd.concat([ndx, sp5, vix], axis=1).ffill()

    _weather_cache[cache_key] = weather_df
    return weather_df



def send_tournament_results(tournament_report: str):
    """
    AI 토너먼트 결과를 AI별로 분리해서 개별 전송.
    각 AI 코멘트가 길면 추가 분할.
    """
    if not tournament_report:
        return

    # AI별 섹션 분리 마커
    markers = [
        ('🧠 [GPT-4o]',        '🧠 GPT-4o 분석'),
        ('🤖 [Claude-Sonnet]', '🤖 Claude-Sonnet 분석'),
        ('♊ [Gemini-Flash]',  '♊ Gemini-Flash 분석'),
        ('⚡ [Groq-Llama]',    '⚡ Groq-Llama 분석'),
    ]

    # 헤더 분리
    header_end = tournament_report.find('\n\n🧠')
    for _mark in ['\n\n🤖', '\n\n♊', '\n\n⚡']:
        if header_end == -1:
            header_end = tournament_report.find(_mark)

    header = tournament_report[:header_end].strip() if header_end > 0 else '🏆 AI 토너먼트 결과'

    # 헤더 먼저 전송
    send_telegram_photo(header, [])

    # 각 AI 섹션 찾아서 개별 전송
    sent_any = False
    for marker, title in markers:
        start = tournament_report.find(marker)
        if start == -1:
            continue

        # 다음 AI 섹션 시작 위치 찾기
        end = len(tournament_report)
        for other_marker, _ in markers:
            if other_marker == marker:
                continue
            pos = tournament_report.find(other_marker, start + len(marker))
            if pos != -1 and pos < end:
                end = pos

        section = tournament_report[start:end].strip()
        if section:
            send_telegram_chunks(section, title=title, max_len=3500)
            sent_any = True

    # 마커를 못 찾으면 전체를 분할 전송
    if not sent_any:
        send_telegram_chunks(tournament_report, max_len=3500)

